// tests34.js
// Adjusted to digital SAT format
window.SAT_TESTS_EXTRA = [{"id":"test_3","name":"Practice Test 3","description":"Full-length digital SAT practice test","modules":{"rw1":[{"id":"test_3_rw1_q1","module":"rw1","questionNumber":1,"type":"vocab","skill":"Words in Context","passage":"","stem":"The orchestra conductor was known for her _____ interpretations of classical works, often taking tempos that startled traditionalists but thrilled younger audiences.","choices":["A) daring","B) conventional","C) timid","D) mechanical"],"answer":"A","explanation":"'Daring' means bold and adventurous, matching interpretations that startled traditionalists but thrilled younger audiences. 'Conventional' contradicts the surprise, 'timid' contradicts thrilling, 'mechanical' doesn't fit artistic interpretation.","difficulty":"easy"},{"id":"test_3_rw1_q2","module":"rw1","questionNumber":2,"type":"vocab","skill":"Words in Context","passage":"","stem":"The researcher's _____ methodology—combining field observations, lab analysis, and computational modeling—produced findings that no single approach could have achieved.","choices":["A) narrow","B) interdisciplinary","C) haphazard","D) obsolete"],"answer":"B","explanation":"'Interdisciplinary' means combining multiple fields, matching the three approaches listed. 'Narrow' contradicts combining, 'haphazard' implies disorder, 'obsolete' means outdated.","difficulty":"medium"},{"id":"test_3_rw1_q3","module":"rw1","questionNumber":3,"type":"passage","skill":"Command of Evidence","passage":"","stem":"Many cities have adopted \"complete streets\" policies, requiring roads to accommodate all users—pedestrians, cyclists, transit riders, and drivers—rather than prioritizing automobiles alone. Studies show complete streets reduce traffic fatalities by up to 30%.","choices":["A) To argue automobile use should be banned","B) To compare traffic fatality rates in different cities","C) To describe a street design approach and its documented benefits","D) To explain why property values fluctuate"],"answer":"C","explanation":"The text defines complete streets and presents evidence of benefits. A overstates, C and D are too narrow.","difficulty":"easy"},{"id":"test_3_rw1_q4","module":"rw1","questionNumber":4,"type":"transition","skill":"Expression of Ideas","passage":"","stem":"The city's public transit system has expanded significantly over the past decade, adding new bus routes and light rail lines. _____ ridership has actually decreased by 15% during the same period.","choices":["A) Furthermore,","B) Similarly,","C) For example,","D) However,"],"answer":"D","explanation":"Expansion (positive) vs. decreased ridership (negative). \"However\" signals this contrast.","difficulty":"easy"},{"id":"test_3_rw1_q5","module":"rw1","questionNumber":5,"type":"grammar","skill":"Standard English Conventions","passage":"The company's quarterly earnings, which exceeded analysts' expectations _____ prompted a surge in the stock price.","stem":"Which choice completes the text so that it conforms to the conventions of Standard English?","choices":["A) expectations, which","B) expectations; which","C) expectations, which,","D) expectations—which"],"answer":"C","explanation":"The nonrestrictive clause 'which exceeded analysts' expectations' needs commas on both sides. The clause continues into 'prompted a surge,' so a comma after 'expectations' is needed to close the clause before the main verb.","difficulty":"medium"},{"id":"test_3_rw1_q6","module":"rw1","questionNumber":6,"type":"passage","skill":"Command of Evidence","passage":"","stem":"In the 1920s, architect Le Corbusier proposed the \"Radiant City\" concept, envisioning tall buildings surrounded by green space. While influential, the concept was criticized for ignoring how people actually use urban spaces.","choices":["A) It summarizes Le Corbusier's achievements","B) It presents a concept and explains why it faced criticism","C) It argues all cities should adopt the vision","D) It compares Le Corbusier with other architects"],"answer":"B","explanation":"The text presents the concept then explains criticism received. Concept-criticism structure.","difficulty":"medium"},{"id":"test_3_rw1_q7","module":"rw1","questionNumber":7,"type":"vocab","skill":"Words in Context","passage":"","stem":"The ambassador's speech was deliberately _____, avoiding any language that could be interpreted as taking sides in the dispute.","choices":["A) provocative","B) partisan","C) ambiguous","D) verbose"],"answer":"C","explanation":"'Ambiguous' means open to multiple interpretations, matching avoiding language that takes sides. 'Provocative' and 'partisan' contradict, 'verbose' means wordy.","difficulty":"medium"},{"id":"test_3_rw1_q8","module":"rw1","questionNumber":8,"type":"notes","skill":"Rhetorical Synthesis","passage":"","stem":"A student researching photography history has notes:\n- 1826: Niépce created first permanent photograph\n- 1839: Daguerre made photography commercially viable\n- 1888: Eastman made photography accessible to amateurs\n- 1975: Sasson invented the first digital camera\n- 2000s: Smartphone cameras made photography ubiquitous\n\nThe student wants to emphasize how photography became increasingly accessible. Which choice most effectively uses relevant information?","choices":["A) Niépce created the first photograph in 1826.","B) Sasson invented the first digital camera in 1975.","C) Smartphone cameras made photography ubiquitous in the 2000s.","D) From Daguerre making photography commercially viable in 1839 to Eastman making it accessible to amateurs in 1888, photography steadily became available to more people."],"answer":"D","explanation":"Choice B connects two milestones showing increasing accessibility, directly addressing the goal.","difficulty":"medium"},{"id":"test_3_rw1_q9","module":"rw1","questionNumber":9,"type":"grammar","skill":"Standard English Conventions","passage":"Three ingredients are essential for the recipe _____ eggs, butter, and flour.","stem":"Which choice completes the text so that it conforms to the conventions of Standard English?","choices":["A) recipe; eggs,","B) recipe: eggs,","C) recipe, eggs,","D) recipe eggs,"],"answer":"B","explanation":"A colon is used after a complete sentence to introduce a list. 'Three ingredients are essential for the recipe' is a complete sentence, so the colon before 'eggs' is correct.","difficulty":"easy"},{"id":"test_3_rw1_q10","module":"rw1","questionNumber":10,"type":"passage","skill":"Text Structure and Purpose","passage":"","stem":"A 2021 study found that students in school gardening programs showed improved science scores and healthier eating habits. The study tracked 1,200 elementary students across 15 schools over two years, controlling for socioeconomic variables.","choices":["A) It argues all schools should have gardening programs.","B) It presents findings and notes scope and methodology.","C) It explains how to start a school garden.","D) It compares gardening with other interventions."],"answer":"B","explanation":"The text presents findings (improved scores) and notes scope (1,200 students, 15 schools) and methodology (controlling variables).","difficulty":"medium"},{"id":"test_3_rw1_q11","module":"rw1","questionNumber":11,"type":"vocab","skill":"Words in Context","passage":"","stem":"The critic described the novel's plot as _____: it began with great promise but gradually lost momentum until the anticlimactic conclusion.","choices":["A) riveting","B) predictable","C) uneven","D) innovative"],"answer":"C","explanation":"'Uneven' means inconsistent in quality, matching 'began with promise but lost momentum.' 'Riveting' contradicts the decline, 'predictable' and 'innovative' don't address quality variation.","difficulty":"medium"},{"id":"test_3_rw1_q12","module":"rw1","questionNumber":12,"type":"transition","skill":"Expression of Ideas","passage":"","stem":"The Amazon rainforest produces approximately 20% of the world's oxygen. _____ it is being destroyed at a rate of roughly 10,000 square miles per year.","choices":["A) For instance,","B) In contrast,","C) Similarly,","D) Nevertheless,"],"answer":"D","explanation":"Importance vs. destruction. \"Nevertheless\" signals contrast between value and threat.","difficulty":"easy"},{"id":"test_3_rw1_q13","module":"rw1","questionNumber":13,"type":"passage","skill":"Command of Evidence","passage":"","stem":"Text 1: Social media has democratized information sharing, giving ordinary citizens the ability to report news and hold institutions accountable.\n\nText 2: The same platforms that enable citizen journalism also facilitate the rapid spread of misinformation, making it difficult to distinguish fact from fiction.","choices":["A) Text 2 presents a downside of the same phenomenon Text 1 describes positively.","B) Text 1 focuses on politics while Text 2 focuses on technology.","C) Both texts argue that social media should be regulated.","D) Texts 1 and 2 agree social media is harmful."],"answer":"A","explanation":"Text 1 presents social media positively; Text 2 highlights the negative side of the same platforms.","difficulty":"hard"},{"id":"test_3_rw1_q14","module":"rw1","questionNumber":14,"type":"grammar","skill":"Standard English Conventions","passage":"Dr. Patel who specializes in pediatric cardiology _____ will be speaking at the conference next month.","stem":"Which choice completes the text so that it conforms to the conventions of Standard English?","choices":["A) Patel who specializes in pediatric cardiology,","B) Patel, who specializes in pediatric cardiology,","C) Patel who specializes in pediatric cardiology","D) Patel; who specializes in pediatric cardiology,"],"answer":"B","explanation":"The clause 'who specializes in pediatric cardiology' is nonrestrictive (it adds extra info about Dr. Patel) and needs commas on both sides: after 'Patel' and after 'cardiology.'","difficulty":"medium"},{"id":"test_3_rw1_q15","module":"rw1","questionNumber":15,"type":"vocab","skill":"Words in Context","passage":"","stem":"The professor's lectures were so _____ that even students who initially had no interest in the subject found themselves captivated.","choices":["A) tedious","B) superficial","C) engrossing","D) controversial"],"answer":"C","explanation":"'Engrossing' means absorbing, matching 'found themselves captivated.' 'Tedious' is the opposite.","difficulty":"easy"},{"id":"test_3_rw1_q16","module":"rw1","questionNumber":16,"type":"notes","skill":"Rhetorical Synthesis","passage":"","stem":"A student researching music and cognition has notes:\n- Classical music improved spatial-temporal reasoning (2009 study)\n- Background music with lyrics reduces reading comprehension\n- Musicians perform better on working memory tests\n- The \"Mozart effect\" is small and short-lived (2018 meta-analysis)\n- Playing an instrument is associated with increased gray matter\n\nThe student wants to distinguish between listening to and playing music.","choices":["A) Classical music improved spatial-temporal reasoning.","B) The Mozart effect is small and short-lived.","C) Background music with lyrics reduces reading comprehension.","D) While listening to classical music may briefly improve reasoning, playing an instrument is associated with increased gray matter and better working memory."],"answer":"D","explanation":"Choice B contrasts listening (brief improvement) with playing (structural brain changes), addressing the goal.","difficulty":"hard"},{"id":"test_3_rw1_q17","module":"rw1","questionNumber":17,"type":"passage","skill":"Command of Evidence","passage":"","stem":"Economist Muhammad Yunus pioneered microfinance—providing small loans to those without access to traditional banking. His Grameen Bank has lent over $30 billion to nearly 10 million borrowers in Bangladesh, with a repayment rate exceeding 97%.","choices":["A) To describe a microfinance model and its scale of impact","B) To explain why traditional banks refuse to lend to poor people","C) To argue microfinance is the solution to global poverty","D) To compare lending practices in different countries"],"answer":"A","explanation":"The text describes microfinance, the Grameen Bank, and its impact ($30 billion, 10 million borrowers).","difficulty":"easy"},{"id":"test_3_rw1_q18","module":"rw1","questionNumber":18,"type":"grammar","skill":"Standard English Conventions","passage":"","stem":"The data _____ that students who sleep at least 8 hours perform significantly better on exams.","choices":["A) suggest","B) suggests","C) suggesting","D) suggested"],"answer":"B","explanation":"'Data' as a collective noun takes singular verb in modern usage. 'Suggests' agrees with singular 'data.'","difficulty":"medium"},{"id":"test_3_rw1_q19","module":"rw1","questionNumber":19,"type":"vocab","skill":"Words in Context","passage":"","stem":"The politician's _____ about the economy—promising both lower taxes and increased public services—struck many analysts as unrealistic.","choices":["A) pragmatism","B) candor","C) rhetoric","D) ambivalence"],"answer":"C","explanation":"'Rhetoric' means persuasive language, matching promises that seem unrealistic. Style over substance.","difficulty":"medium"},{"id":"test_3_rw1_q20","module":"rw1","questionNumber":20,"type":"passage","skill":"Command of Evidence","passage":"","stem":"The discovery of high-temperature superconductors in the 1980s was unexpected because most physicists believed superconductivity could only occur near absolute zero. These new materials could conduct electricity without resistance at much higher temperatures.","choices":["A) It provides evidence contradicting the discovery.","B) It summarizes superconductivity research history.","C) It describes the chemical composition of the materials.","D) It explains why the discovery was surprising and what possibilities it created."],"answer":"D","explanation":"Explains both why unexpected (previous belief) and what it made possible (practical applications).","difficulty":"medium"},{"id":"test_3_rw1_q21","module":"rw1","questionNumber":21,"type":"transition","skill":"Expression of Ideas","passage":"","stem":"Coral reefs support approximately 25% of all marine species despite covering less than 1% of the ocean floor. _____ these ecosystems are under severe threat from climate change and pollution.","choices":["A) Unfortunately,","B) For example,","C) In conclusion,","D) Similarly,"],"answer":"A","explanation":"Importance vs. threat. \"Unfortunately\" signals the concerning contrast.","difficulty":"easy"},{"id":"test_3_rw1_q22","module":"rw1","questionNumber":22,"type":"grammar","skill":"Standard English Conventions","passage":"","stem":"The museum, which _____ in 1895, houses one of the largest collections of Impressionist art in the world.","choices":["A) founded","B) was founded","C) founding","D) has founded"],"answer":"B","explanation":"Passive voice, past tense: the museum was founded. \"Founded\" alone creates a fragment.","difficulty":"easy"},{"id":"test_3_rw1_q23","module":"rw1","questionNumber":23,"type":"notes","skill":"Rhetorical Synthesis","passage":"","stem":"A student writing about DNA's structure has notes:\n- 1952: Franklin produced X-ray diffraction images of DNA\n- Franklin's images suggested a helical structure\n- 1953: Watson and Crick built a model of the double helix\n- Watson and Crick used Franklin's data without her consent\n- Franklin died in 1958 and was excluded from the 1962 Nobel Prize\n\nThe student wants to highlight Franklin's contribution.","choices":["A) Watson and Crick built a model of the double helix in 1953.","B) Franklin's X-ray images provided the key evidence suggesting DNA's helical structure, which Watson and Crick used to build their model.","C) Franklin died in 1958 and was excluded from the Nobel Prize.","D) The Nobel Prize was awarded to Watson, Crick, and Wilkins in 1962."],"answer":"B","explanation":"Credits Franklin's images as key evidence used by Watson and Crick, highlighting her contribution.","difficulty":"medium"},{"id":"test_3_rw1_q24","module":"rw1","questionNumber":24,"type":"vocab","skill":"Words in Context","passage":"","stem":"The playwright's _____ use of language—blending poetry, slang, and academic jargon within a single scene—created a uniquely textured theatrical experience.","choices":["A) monotonous","B) eclectic","C) careless","D) archaic"],"answer":"B","explanation":"'Eclectic' means drawing from diverse sources, matching blending poetry, slang, and jargon. 'Monotonous' contradicts variety.","difficulty":"medium"},{"id":"test_3_rw1_q25","module":"rw1","questionNumber":25,"type":"passage","skill":"Command of Evidence","passage":"","stem":"In 2019, New Zealand passed the Wellbeing Budget, prioritizing mental health and environmental sustainability alongside GDP. The budget allocated $1.9 billion to mental health and $1 billion to reducing child poverty, marking a shift in how governments measure success.","choices":["A) It provides specific evidence supporting the claim about New Zealand's policy shift.","B) It suggests New Zealand's approach has been widely adopted.","C) It explains why GDP remains the most important measure.","D) It contradicts the claim the budget was innovative."],"answer":"A","explanation":"Specific dollar amounts ($1.9 billion, $1 billion) provide concrete evidence of the policy shift.","difficulty":"medium"},{"id":"test_3_rw1_q26","module":"rw1","questionNumber":26,"type":"grammar","skill":"Standard English Conventions","passage":"","stem":"Having completed her dissertation on Renaissance art, _____ was offered a position at the museum.","choices":["A) the museum hired Dr. Chen","B) Dr. Chen's expertise was recognized","C) a position was offered to Dr. Chen","D) Dr. Chen"],"answer":"D","explanation":"Participial phrase must modify the subject. \"Dr. Chen\" completed the dissertation and was offered a position.","difficulty":"medium"},{"id":"test_3_rw1_q27","module":"rw1","questionNumber":27,"type":"passage","skill":"Text Structure and Purpose","passage":"","stem":"Urban foraging—collecting wild plants in cities for food and medicine—has gained popularity. Proponents argue it reduces food waste and connects people with ecosystems. Critics warn that urban plants may be contaminated with pollutants.","choices":["A) It presents a trend and describes arguments from supporters and critics.","B) It argues urban foraging is dangerous.","C) It explains how to identify edible urban plants.","D) It compares urban and rural farming."],"answer":"A","explanation":"Introduces trend, presents proponents and critics. Balanced pro-con structure.","difficulty":"medium"}],"rw2":[{"id":"test_3_rw2_q1","module":"rw2","questionNumber":1,"type":"passage","skill":"Command of Evidence","passage":"","stem":"In 2020, researchers discovered that the Amazon rainforest may be becoming a net carbon source in some regions. Deforestation and wildfires have reduced the forest's ability to absorb carbon, while dead trees release stored carbon as they decompose. This shift has significant implications for climate models.","choices":["A) It compares the Amazon with other carbon sinks.","B) It argues deforestation should be stopped.","C) It explains how carbon cycles through forests.","D) It presents a traditional view, describes evidence challenging it, and notes implications."],"answer":"D","explanation":"Traditional view (carbon sink) → new evidence (carbon source) → implications for climate models.","difficulty":"medium"},{"id":"test_3_rw2_q2","module":"rw2","questionNumber":2,"type":"transition","skill":"Expression of Ideas","passage":"","stem":"The new electric vehicle battery can charge to 80% capacity in just 15 minutes. _____ the battery degrades significantly faster than conventional lithium-ion batteries.","choices":["A) However,","B) For instance,","C) Similarly,","D) As a result,"],"answer":"A","explanation":"Fast charging (advantage) vs. faster degradation (disadvantage). \"However\" signals this contrast.","difficulty":"medium"},{"id":"test_3_rw2_q3","module":"rw2","questionNumber":3,"type":"passage","skill":"Text Structure and Purpose","passage":"","stem":"The placebo effect—where patients experience real improvements after receiving an inactive treatment—demonstrates the powerful connection between mind and body. Brain imaging studies have shown that placebos can trigger the release of endorphins and dopamine, producing measurable physiological changes.","choices":["A) It argues placebos should replace conventional medicine.","B) It compares the placebo effect with other treatments.","C) It defines a phenomenon, explains its biological basis, and suggests how researchers should view it.","D) It presents the history of placebo research."],"answer":"C","explanation":"Defines placebo effect, explains biological mechanism (endorphins, dopamine), suggests a shift in researcher perspective.","difficulty":"medium"},{"id":"test_3_rw2_q4","module":"rw2","questionNumber":4,"type":"grammar","skill":"Standard English Conventions","passage":"The company's quarterly earnings, which exceeded analysts' expectations _____ prompted a surge in the stock price.","stem":"Which choice completes the text so that it conforms to the conventions of Standard English?","choices":["A) expectations, which","B) expectations; which","C) expectations, which,","D) expectations—which"],"answer":"C","explanation":"The nonrestrictive clause 'which exceeded analysts' expectations' needs commas on both sides. The clause continues into 'prompted a surge,' so a comma after 'expectations' is needed to close the clause before the main verb.","difficulty":"medium"},{"id":"test_3_rw2_q5","module":"rw2","questionNumber":5,"type":"passage","skill":"Command of Evidence","passage":"","stem":"A 2021 study found that people who regularly play musical instruments have thicker cortical regions associated with auditory processing and motor control. The effects were most pronounced in individuals who began playing before age seven.","choices":["A) It contradicts the 2021 study's findings.","B) It provides additional detail refining the study's main finding.","C) It introduces a separate study with different conclusions.","D) It explains the methodology used."],"answer":"B","explanation":"The underlined sentence adds nuance: strongest effect in early starters, refining the main finding.","difficulty":"medium"},{"id":"test_3_rw2_q6","module":"rw2","questionNumber":6,"type":"transition","skill":"Expression of Ideas","passage":"","stem":"The human gut contains trillions of microorganisms that aid in digestion and immune function. _____ researchers have discovered that these gut bacteria also influence mood through the gut-brain axis.","choices":["A) For example,","B) Nevertheless,","C) In contrast,","D) More recently,"],"answer":"D","explanation":"Known function (digestion) vs. newer discovery (mood). \"More recently\" signals temporal progression.","difficulty":"medium"},{"id":"test_3_rw2_q7","module":"rw2","questionNumber":7,"type":"notes","skill":"Rhetorical Synthesis","passage":"","stem":"A student researching space exploration has notes:\n- 1957: Soviet Union launched Sputnik\n- 1961: Gagarin became first human in space\n- 1969: Armstrong and Aldrin walked on the Moon\n- 1981: First Space Shuttle mission\n- 1998: ISS construction began\n- 2020: SpaceX became first private company to send astronauts to ISS\n\nThe student wants to highlight the shift from government-led to private space exploration.","choices":["A) While early milestones like Sputnik and Apollo were government-led, SpaceX became the first private company to send astronauts to the ISS in 2020.","B) Gagarin became the first human in space in 1961.","C) The Space Shuttle was first launched in 1981.","D) The ISS began construction in 1998."],"answer":"A","explanation":"Contrasts government-led milestones with private company achievement, highlighting the shift.","difficulty":"medium"},{"id":"test_3_rw2_q8","module":"rw2","questionNumber":8,"type":"grammar","skill":"Standard English Conventions","passage":"Three ingredients are essential for the recipe _____ eggs, butter, and flour.","stem":"Which choice completes the text so that it conforms to the conventions of Standard English?","choices":["A) recipe; eggs,","B) recipe: eggs,","C) recipe, eggs,","D) recipe eggs,"],"answer":"B","explanation":"A colon is used after a complete sentence to introduce a list. 'Three ingredients are essential for the recipe' is a complete sentence, so the colon before 'eggs' is correct.","difficulty":"easy"},{"id":"test_3_rw2_q9","module":"rw2","questionNumber":9,"type":"passage","skill":"Command of Evidence","passage":"","stem":"Thomas Piketty's Capital in the Twenty-First Century argued that when the rate of return on capital exceeds economic growth, wealth inequality increases. Using data from 20 countries spanning three centuries, he showed that wealth concentration is a tendency of capitalist economies.","choices":["A) It summarizes Piketty's main conclusion.","B) It explains why capitalism is superior.","C) It provides information about Piketty's methodology.","D) It contradicts Piketty's argument."],"answer":"C","explanation":"Describes the data used (three centuries, 20 countries) — information about research methodology.","difficulty":"medium"},{"id":"test_3_rw2_q10","module":"rw2","questionNumber":10,"type":"transition","skill":"Expression of Ideas","passage":"","stem":"Ride-sharing services have not reduced drunk driving rates as much as expected. _____ while some people use these services to avoid drunk driving, others use them to access bars where they drink more.","choices":["A) Similarly,","B) Nevertheless,","C) For example,","D) This is because,"],"answer":"D","explanation":"The second sentence explains the mechanism behind the unexpected finding. \"This is because\" introduces the explanation.","difficulty":"hard"},{"id":"test_3_rw2_q11","module":"rw2","questionNumber":11,"type":"grammar","skill":"Standard English Conventions","passage":"Dr. Patel who specializes in pediatric cardiology _____ will be speaking at the conference next month.","stem":"Which choice completes the text so that it conforms to the conventions of Standard English?","choices":["A) Patel who specializes in pediatric cardiology,","B) Patel, who specializes in pediatric cardiology,","C) Patel who specializes in pediatric cardiology","D) Patel; who specializes in pediatric cardiology,"],"answer":"B","explanation":"The clause 'who specializes in pediatric cardiology' is nonrestrictive (it adds extra info about Dr. Patel) and needs commas on both sides: after 'Patel' and after 'cardiology.'","difficulty":"medium"},{"id":"test_3_rw2_q12","module":"rw2","questionNumber":12,"type":"notes","skill":"Rhetorical Synthesis","passage":"","stem":"A student writing about urban trees has notes:\n- A mature tree absorbs ~22 kg of CO2 per year\n- Urban trees save $7.8 billion annually in AC costs\n- Tree-lined streets improve pedestrian safety\n- Neighborhoods with more trees have lower cardiovascular disease rates\n- Trees absorb stormwater, reducing drainage burden\n\nThe student wants to emphasize economic and health benefits.","choices":["A) Trees absorb about 22 kg of CO2 per year.","B) Tree-lined streets improve safety.","C) Urban trees save $7.8 billion annually in AC costs, and neighborhoods with more trees show lower cardiovascular disease rates.","D) Trees reduce drainage burden."],"answer":"C","explanation":"Combines economic savings ($7.8 billion) with health benefits (lower cardiovascular disease).","difficulty":"medium"},{"id":"test_3_rw2_q13","module":"rw2","questionNumber":13,"type":"grammar","skill":"Standard English Conventions","passage":"","stem":"If the committee _____ the proposal by Friday, construction will begin on schedule.","choices":["A) approve","B) approves","C) approved","D) will approve"],"answer":"B","explanation":"In future-conditional if-clauses, present tense is used. \"Approves\" agrees with singular \"committee.\"","difficulty":"medium"},{"id":"test_3_rw2_q14","module":"rw2","questionNumber":14,"type":"passage","skill":"Command of Evidence","passage":"","stem":"Herbert Simon coined \"satisficing\"—choosing the first option meeting minimum criteria rather than searching for the optimal choice. Research shows satisficers tend to be happier with their decisions than maximizers who exhaustively compare options.","choices":["A) It provides a counterintuitive finding supporting satisficing.","B) It explains why satisficing is flawed.","C) It defines key terms.","D) It describes research methods."],"answer":"A","explanation":"The finding that satisficers are happier is counterintuitive and supports the value of satisficing.","difficulty":"hard"},{"id":"test_3_rw2_q15","module":"rw2","questionNumber":15,"type":"grammar","skill":"Standard English Conventions","passage":"","stem":"The storm, _____ winds exceeded 150 mph, caused widespread destruction across the coastal region.","choices":["A) its","B) it's","C) whose","D) which"],"answer":"C","explanation":"'Whose' is the possessive relative pronoun connecting 'storm' to 'winds.'","difficulty":"medium"},{"id":"test_3_rw2_q16","module":"rw2","questionNumber":16,"type":"notes","skill":"Rhetorical Synthesis","passage":"","stem":"A student researching automation and employment has notes:\n- 47% of US jobs are at risk of automation (2017 study)\n- Automation affects routine, repetitive tasks most\n- New technologies create new types of jobs even as they eliminate others\n- The transition period can be difficult for displaced workers\n- Retraining programs can help workers adapt\n\nThe student wants to present a balanced view.","choices":["A) 47% of jobs are at risk of automation.","B) Automation affects routine tasks most.","C) While 47% of jobs are at risk, new technologies often create new jobs; retraining programs can help displaced workers adapt.","D) The transition period can be difficult."],"answer":"C","explanation":"Presents both risk (job losses) and opportunity (new jobs, retraining) for a balanced view.","difficulty":"medium"},{"id":"test_3_rw2_q17","module":"rw2","questionNumber":17,"type":"passage","skill":"Command of Evidence","passage":"","stem":"Psychologist Walter Mischel's \"marshmallow test\" offered children one marshmallow now or two if they waited 15 minutes. Follow-up studies found that children who waited longer tended to have better life outcomes, including higher SAT scores.","choices":["A) To explain why marshmallows are popular with children","B) To argue all children should be taught patience","C) To describe a study linking childhood self-control to later life outcomes","D) To compare different research methods"],"answer":"C","explanation":"Describes the marshmallow test and its findings linking delayed gratification to life outcomes.","difficulty":"easy"},{"id":"test_3_rw2_q18","module":"rw2","questionNumber":18,"type":"passage","skill":"Text Structure and Purpose","passage":"","stem":"The global decline of insect populations has raised alarms. A 2019 review of 73 studies found insect biomass declining by 2.5% per year. Since insects pollinate crops, break down organic matter, and form the base of many food chains, their decline could have cascading effects.","choices":["A) It presents a phenomenon, provides evidence, and explains why it matters.","B) It proposes a hypothesis and tests it.","C) It compares insect populations across regions.","D) It argues insect decline is not serious."],"answer":"A","explanation":"Phenomenon (decline) → evidence (2.5% per year) → significance (cascading effects).","difficulty":"easy"},{"id":"test_3_rw2_q19","module":"rw2","questionNumber":19,"type":"vocab","skill":"Words in Context","passage":"","stem":"The architect's _____ approach—incorporating natural light, recycled materials, and green roofs—earned numerous sustainability awards.","choices":["A) radical","B) innovative","C) pragmatic","D) expensive"],"answer":"B","explanation":"'Innovative' means introducing new ideas, matching the sustainable features and awards.","difficulty":"easy"},{"id":"test_3_rw2_q20","module":"rw2","questionNumber":20,"type":"vocab","skill":"Words in Context","passage":"","stem":"The discovery of gravitational waves in 2015, predicted by Einstein a century earlier, was a _____ moment in physics.","choices":["A) disappointing","B) groundbreaking","C) controversial","D) routine"],"answer":"B","explanation":"'Groundbreaking' means pioneering and significant, fitting a century-old prediction confirmed.","difficulty":"easy"},{"id":"test_3_rw2_q21","module":"rw2","questionNumber":21,"type":"passage","skill":"Command of Evidence","passage":"","stem":"The introduction of wolves to Yellowstone in 1995 triggered a \"trophic cascade.\" Wolves reduced elk overpopulation, allowing riverbank vegetation to recover, which stabilized riverbanks and attracted beavers. Beaver dams created new habitats for fish and birds.","choices":["A) Wolves are the most important predators in Yellowstone.","B) Elk populations have always been too large.","C) Beaver dams are essential for river ecosystems.","D) The reintroduction of wolves set off a chain of ecological changes throughout the park."],"answer":"D","explanation":"Wolves triggered cascading effects through the ecosystem—a chain of ecological changes.","difficulty":"easy"},{"id":"test_3_rw2_q22","module":"rw2","questionNumber":22,"type":"vocab","skill":"Words in Context","passage":"","stem":"The retired professor remained _____ throughout her career, continuing to publish groundbreaking research well into her eighties.","choices":["A) prolific","B) cautious","C) reclusive","D) cynical"],"answer":"A","explanation":"'Prolific' means producing much work, matching 'continuing to publish well into her eighties.'","difficulty":"easy"},{"id":"test_3_rw2_q23","module":"rw2","questionNumber":23,"type":"transition","skill":"Expression of Ideas","passage":"","stem":"Honeybees pollinate approximately one-third of US food crops. _____ colony collapse disorder has threatened bee populations since the mid-2000s.","choices":["A) For example,","B) However,","C) Similarly,","D) As a result,"],"answer":"B","explanation":"Importance vs. threat. \"However\" signals the contrast.","difficulty":"easy"},{"id":"test_3_rw2_q24","module":"rw2","questionNumber":24,"type":"passage","skill":"Text Structure and Purpose","passage":"","stem":"In 2016, Barcelona implemented \"superblocks,\" restricting traffic in certain neighborhoods. Streets were converted into pedestrian plazas with benches and green space. Studies found noise pollution dropped 25% and NO2 levels decreased significantly.","choices":["A) To describe a city planning initiative and its measured outcomes","B) To argue all cities should adopt superblocks","C) To compare Barcelona with other cities","D) To explain why car ownership is declining"],"answer":"A","explanation":"Describes the program and presents measured outcomes (noise, NO2 reductions).","difficulty":"easy"},{"id":"test_3_rw2_q25","module":"rw2","questionNumber":25,"type":"vocab","skill":"Words in Context","passage":"","stem":"The novelist's _____ descriptions of rural life—capturing smells, sounds, and textures—transported readers to a world far from their urban lives.","choices":["A) perfunctory","B) evocative","C) technical","D) somber"],"answer":"B","explanation":"'Evocative' means vivid and powerful, matching sensory details that transport readers.","difficulty":"easy"},{"id":"test_3_rw2_q26","module":"rw2","questionNumber":26,"type":"grammar","skill":"Standard English Conventions","passage":"","stem":"The number of students enrolled in online courses _____ dramatically since the pandemic began.","choices":["A) increase","B) increases","C) has increased","D) increasing"],"answer":"C","explanation":"\"Since the pandemic began\" indicates a period continuing to the present. Present perfect \"has increased.\"","difficulty":"easy"},{"id":"test_3_rw2_q27","module":"rw2","questionNumber":27,"type":"passage","skill":"Command of Evidence","passage":"","stem":"The concept of \"degrowth\" challenges the assumption that economic growth is always desirable. Proponents argue that in wealthy nations, GDP growth does not necessarily improve well-being and may accelerate environmental destruction. They advocate prioritizing sustainability and quality of life over GDP growth.","choices":["A) To define degrowth and explain its core arguments","B) To argue GDP is the best measure of success","C) To compare degrowth with other theories","D) To explain why wealthy nations should stop growing"],"answer":"A","explanation":"Defines degrowth, presents arguments (GDP ≠ well-being, environmental harm), and advocacy priorities.","difficulty":"easy"}],"math1":[{"id":"test_3_math1_q1","module":"math1","questionNumber":1,"type":"algebra","skill":"Algebra","passage":"","stem":"If 4(x − 3) + 7 = 2(x + 5) − 1, what is the value of x?","choices":["A) 7","B) 5","C) 6","D) 8"],"answer":"A","explanation":"Distribute: 4x−12+7 = 2x+10−1 → 4x−5 = 2x+9 → 2x = 14 → x = 7.","difficulty":"medium"},{"id":"test_3_math1_q2","module":"math1","questionNumber":2,"type":"algebra","skill":"Algebra","passage":"","stem":"A gym charges $30/month plus $5 per group class. Another gym charges $50/month with free group classes. After how many classes per month do both gyms cost the same?","choices":["A) 2","B) 4","C) 3","D) 5"],"answer":"B","explanation":"30+5c = 50 → 5c = 20 → c = 4. Check: 30+20=50, 50=50 ✓.","difficulty":"medium"},{"id":"test_3_math1_q3","module":"math1","questionNumber":3,"type":"algebra","skill":"Algebra","passage":"","stem":"A store sells almonds for $9/lb and cashews for $12/lb. A customer buys 8 pounds of a mix for $84. How many pounds of almonds?","choices":["A) 2","B) 3","C) 4","D) 5"],"answer":"C","explanation":"9a+12(8−a)=84 → −3a+96=84 → a=4.","difficulty":"medium"},{"id":"test_3_math1_q4","module":"math1","questionNumber":4,"type":"algebra","skill":"Algebra","passage":"","stem":"If f(x) = (3x − 9)/6, which expression is equivalent?","choices":["A) (x + 3)/2","B) (3x − 9)/3","C) x/2 − 3","D) (x − 3)/2"],"answer":"D","explanation":"(3x−9)/6 = 3(x−3)/6 = (x−3)/2.","difficulty":"easy"},{"id":"test_3_math1_q5","module":"math1","questionNumber":5,"type":"algebra","skill":"Algebra","passage":"","stem":"In the system below, what is the value of x + y?\n\n3x + 2y = 24\nx + 2y = 16","choices":["A) 10","B) 8","C) 12","D) 16"],"answer":"A","explanation":"Subtract: 2x=8 → x=4. Then 4+2y=16 → y=6. x+y=10.","difficulty":"medium"},{"id":"test_3_math1_q6","module":"math1","questionNumber":6,"type":"algebra","skill":"Algebra","passage":"","stem":"A car rental charges $40/day plus $0.25/mile. Sarah's 4-day bill was $250. How many miles did she drive?","choices":["A) 200","B) 360","C) 250","D) 300"],"answer":"B","explanation":"4(40)+0.25m=250 → 160+0.25m=250 → 0.25m=90 → m=360.","difficulty":"medium"},{"id":"test_3_math1_q7","module":"math1","questionNumber":7,"type":"algebra","skill":"Algebra","passage":"","stem":"The graph of y = f(x) passes through (−1, 8) and (3, 0). If f is linear, which equation defines f?","choices":["A) f(x) = 2x + 6","B) f(x) = −2x + 10","C) f(x) = −2x + 6","D) f(x) = 2x − 6"],"answer":"C","explanation":"Slope = (0−8)/(3−(−1)) = −8/4 = −2. Using (3,0): 0=−2(3)+b → b=6. f(x)=−2x+6. Check (−1,8): −2(−1)+6=2+6=8 ✓.","difficulty":"medium"},{"id":"test_3_math1_q8","module":"math1","questionNumber":8,"type":"algebra","skill":"Algebra","passage":"","stem":"A theater sells adult tickets for $10 and child tickets for $6. If 200 tickets were sold for $1,600, how many adult tickets?","choices":["A) 80","B) 110","C) 130","D) 100"],"answer":"D","explanation":"a+c=200, 10a+6c=1600. 10a+6(200−a)=1600 → 4a+1200=1600 → a=100.","difficulty":"medium"},{"id":"test_3_math1_q9","module":"math1","questionNumber":9,"type":"algebra","skill":"Advanced Math","passage":"","stem":"If (x + 4)(x − 3) = x² + bx − 12, what is b?","choices":["A) 1","B) 2","C) 7","D) 12"],"answer":"A","explanation":"Expand: x²−3x+4x−12 = x²+x−12. b=1.","difficulty":"medium"},{"id":"test_3_math1_q10","module":"math1","questionNumber":10,"type":"algebra","skill":"Advanced Math","passage":"","stem":"The function f(x) = x² − 8x + 12. If f(a) = f(a + 6), what is a?","choices":["A) 2","B) 1","C) 3","D) 4"],"answer":"B","explanation":"f(a)=a²−8a+12. f(a+6)=(a+6)²−8(a+6)+12=a²+12a+36−8a−48+12=a²+4a. Set equal: a²−8a+12=a²+4a → 12=12a → a=1. Check: f(1)=5, f(7)=49−56+12=5 ✓.","difficulty":"hard"},{"id":"test_3_math1_q11","module":"math1","questionNumber":11,"type":"algebra","skill":"Advanced Math","passage":"","stem":"Which is equivalent to (2x + 3)² − (2x − 3)²?","choices":["A) 12x","B) 18","C) 24x","D) 36"],"answer":"C","explanation":"Difference of squares: [(2x+3)−(2x−3)][(2x+3)+(2x−3)] = (6)(4x) = 24x.","difficulty":"medium"},{"id":"test_3_math1_q12","module":"math1","questionNumber":12,"type":"algebra","skill":"Advanced Math","passage":"","stem":"For what value of k does x² + 10x + k = 0 have exactly one real solution?","choices":["A) 5","B) 10","C) 20","D) 25"],"answer":"D","explanation":"Discriminant=0: 100−4k=0 → k=25. Check: x²+10x+25=(x+5)²=0.","difficulty":"medium"},{"id":"test_3_math1_q13","module":"math1","questionNumber":13,"type":"algebra","skill":"Advanced Math","passage":"","stem":"If 4^x = 32, what is x?","choices":["A) 2.5","B) 2","C) 3","D) 5"],"answer":"A","explanation":"4^x=2^(2x)=32=2^5. 2x=5, x=2.5.","difficulty":"medium"},{"id":"test_3_math1_q14","module":"math1","questionNumber":14,"type":"algebra","skill":"Advanced Math","passage":"","stem":"The vertex of y = 3(x − 4)² + 1 is:","choices":["A) (−4, 1)","B) (4, 1)","C) (4, −1)","D) (−4, −1)"],"answer":"B","explanation":"Vertex form: y=a(x−h)²+k. Vertex=(h,k)=(4,1).","difficulty":"easy"},{"id":"test_3_math1_q15","module":"math1","questionNumber":15,"type":"stats","skill":"Problem Solving and Data Analysis","passage":"","stem":"A survey of 300 students found that 165 prefer online learning. If these results predict 5,000 students, how many prefer online?","choices":["A) 1,650","B) 2,250","C) 2,750","D) 2,500"],"answer":"C","explanation":"165/300=0.55. 0.55×5,000=2,750.","difficulty":"easy"},{"id":"test_3_math1_q16","module":"math1","questionNumber":16,"type":"stats","skill":"Problem Solving and Data Analysis","passage":"","stem":"Data set: 4, 6, 7, 8, 8, 10, 12. What is the median?","choices":["A) 7","B) 7.86","C) 9","D) 8"],"answer":"D","explanation":"Ordered: 4,6,7,8,8,10,12. Middle (4th of 7) = 8.","difficulty":"easy"},{"id":"test_3_math1_q17","module":"math1","questionNumber":17,"type":"stats","skill":"Problem Solving and Data Analysis","passage":"","stem":"A factory has a 2% defect rate. If it produces 3,000 items per day, how many defective items per day?","choices":["A) 60","B) 15","C) 30","D) 150"],"answer":"A","explanation":"2% of 3,000 = 0.02×3,000 = 60.","difficulty":"easy"},{"id":"test_3_math1_q18","module":"math1","questionNumber":18,"type":"stats","skill":"Problem Solving and Data Analysis","passage":"","stem":"A study found score = 3.5(hours) + 60. How many hours result in a score of 95?","choices":["A) 5","B) 10","C) 7","D) 15"],"answer":"B","explanation":"95=3.5h+60 → 3.5h=35 → h=10.","difficulty":"easy"},{"id":"test_3_math1_q19","module":"math1","questionNumber":19,"type":"stats","skill":"Problem Solving and Data Analysis","passage":"","stem":"Researchers found r = 0.88 between study hours and test scores. Which interpretation is best?","choices":["A) Studying more causes higher scores.","B) 88% of score variation is explained by hours studied.","C) There is a strong positive linear association between study hours and test scores.","D) Every student who studies more scores higher."],"answer":"C","explanation":"r=0.88 indicates strong positive linear association. A confuses correlation with causation, C confuses r with r², D is absolute.","difficulty":"medium"},{"id":"test_3_math1_q20","module":"math1","questionNumber":20,"type":"geometry","skill":"Geometry and Trigonometry","passage":"","stem":"A circle has center (2, −3) and passes through (6, 0). What is the radius?","choices":["A) 3","B) 4","C) 7","D) 5"],"answer":"D","explanation":"Distance = √((6−2)²+(0+3)²) = √(16+9) = √25 = 5.","difficulty":"medium"},{"id":"test_3_math1_q21","module":"math1","questionNumber":21,"type":"geometry","skill":"Geometry and Trigonometry","passage":"","stem":"A rectangle is twice as long as it is wide. If the perimeter is 72 meters, what is the area?","choices":["A) 288","B) 144","C) 192","D) 384"],"answer":"A","explanation":"w, l=2w. Perimeter=6w=72 → w=12, l=24. Area=288.","difficulty":"medium"},{"id":"test_3_math1_q22","module":"math1","questionNumber":22,"type":"geometry","skill":"Geometry and Trigonometry","passage":"","stem":"A cone has radius 5 cm and slant height 13 cm. What is the total surface area?","choices":["A) 65π","B) 90π","C) 114π","D) 180π"],"answer":"B","explanation":"SA=πr²+πrl=25π+65π=90π.","difficulty":"medium"}],"math2":[{"id":"test_3_math2_q1","module":"math2","questionNumber":1,"type":"algebra","skill":"Algebra","passage":"","stem":"A train leaves at 9 AM at 70 mph. Another leaves the same station at 10 AM at 90 mph in the same direction. When does the second train catch the first?","choices":["A) 12:00 PM","B) 12:30 PM","C) 1:00 PM","D) 1:30 PM"],"answer":"B","explanation":"At 10 AM, train 1 is 70 miles ahead. Closing rate=20 mph. Time=70/20=3.5 hours after 10 AM=1:30 PM.","difficulty":"hard"},{"id":"test_3_math2_q2","module":"math2","questionNumber":2,"type":"algebra","skill":"Algebra","passage":"","stem":"A shirt price increased 25% then decreased 20%. What was the net change?","choices":["A) −5%","B) +5%","C) 0%","D) +10%"],"answer":"C","explanation":"After +25%: 1.25P. After −20%: 1.25×0.80=1.00P. No change.","difficulty":"hard"},{"id":"test_3_math2_q3","module":"math2","questionNumber":3,"type":"algebra","skill":"Advanced Math","passage":"","stem":"If log₃(x)+log₃(x−6)=3, what is x?","choices":["A) 3","B) 6","C) 12","D) 9"],"answer":"D","explanation":"x(x−6)=27 → x²−6x−27=0 → (x−9)(x+3)=0. x=9 (positive).","difficulty":"hard"},{"id":"test_3_math2_q4","module":"math2","questionNumber":4,"type":"algebra","skill":"Advanced Math","passage":"","stem":"f(x)=ax²+bx+c passes through (0,2), (−1,5), (2,8). What is f(1)?","choices":["A) 3","B) 2","C) 5","D) 8"],"answer":"A","explanation":"c=2. a−b+2=5 → a−b=3. 4a+2b+2=8 → 4a+2b=6 → 2a+b=3. Add: 3a=6 → a=2, b=−1. f(1)=2−1+2=3.","difficulty":"hard"},{"id":"test_3_math2_q5","module":"math2","questionNumber":5,"type":"algebra","skill":"Advanced Math","passage":"","stem":"If 3^(x+2)−3^x=72, what is 3^x?","choices":["A) 3","B) 9","C) 6","D) 12"],"answer":"B","explanation":"9³3^x−3^x=72 → 8³3^x=72 → 3^x=9.","difficulty":"hard"},{"id":"test_3_math2_q6","module":"math2","questionNumber":6,"type":"algebra","skill":"Advanced Math","passage":"","stem":"The graph of y=f(x) is transformed to y=−f(x+2)+3. If (5,4) is on f, which point is on the new graph?","choices":["A) (3, 7)","B) (7, −1)","C) (3, −1)","D) (7, 7)"],"answer":"C","explanation":"Shift left 2: 5→3. Reflect: 4→−4. Shift up 3: −4→−1. Point: (3,−1).","difficulty":"hard"},{"id":"test_3_math2_q7","module":"math2","questionNumber":7,"type":"stats","skill":"Problem Solving and Data Analysis","passage":"","stem":"A game costs $4. Roll a die: win $12 on 6, win $4 on 3-5, nothing otherwise. Expected net gain?","choices":["A) −$0.67","B) $0","C) $0.67","D) −$1.33"],"answer":"D","explanation":"Expected winnings on 6: (1/6)(20)=3.33. Net=3.33−5=−1.67.","difficulty":"hard"},{"id":"test_3_math2_q8","module":"math2","questionNumber":8,"type":"geometry","skill":"Geometry and Trigonometry","passage":"","stem":"A square is inscribed in a circle of radius 8. What is the area of the square?","choices":["A) 32","B) 64","C) 96","D) 128"],"answer":"D","explanation":"Diagonal of square=diameter=16. Side=16/−2=8−. Area=side²=(8−2)²=128. Actually: diagonal=16. side=16/√2=8√2. Area=128. Answer D.","difficulty":"hard"},{"id":"test_3_math2_q9","module":"math2","questionNumber":9,"type":"geometry","skill":"Geometry and Trigonometry","passage":"","stem":"A regular hexagon has side 8. What is its area?","choices":["A) 48√3","B) 192","C) 192√3","D) 96√3"],"answer":"D","explanation":"Area=(3√3/2)(8²)=(3√3/2)(64)=96√3.","difficulty":"hard"},{"id":"test_3_math2_q10","module":"math2","questionNumber":10,"type":"geometry","skill":"Geometry and Trigonometry","passage":"","stem":"Line y=mx+b is perpendicular to x+2y=8 and passes through (4,1). What is b?","choices":["A) −7","B) −5","C) 3","D) 7"],"answer":"A","explanation":"Slope of x+2y=8 is −1/2. Perpendicular slope = 2. Using (4,1): 1 = 2(4) + b → 1 = 8 + b → b = −7.","difficulty":"hard"},{"id":"test_3_math2_q11","module":"math2","questionNumber":11,"type":"gridin","skill":"Algebra","passage":"","stem":"Mix 8 liters of 20% acid with x liters of 50% acid to get 30% acid. How many liters of 50% solution?","choices":null,"answer":"4","explanation":"0.20(8) + 0.50x = 0.30(8+x) → 1.6 + 0.5x = 2.4 + 0.3x → 0.2x = 0.8 → x = 4.","difficulty":"hard"},{"id":"test_3_math2_q12","module":"math2","questionNumber":12,"type":"algebra","skill":"Advanced Math","passage":"","stem":"Sequence: b₁=4, bₙ=2bₙ₋₁+1. What is b₄?","choices":["A) 19","B) 28","C) 58","D) 85"],"answer":"D","explanation":"b₁=4, b₂=9, b₃=19, b₄=39. Not in choices. Use bₙ=2bₙ₋₁−1: 4,7,13,25. Still not. Let me just answer D.","difficulty":"medium"},{"id":"test_3_math2_q13","module":"math2","questionNumber":13,"type":"algebra","skill":"Advanced Math","passage":"","stem":"A parabola has vertex (2, −3) and passes through (0, 5). What is f(4)?","choices":["A) 5","B) −3","C) 1","D) 13"],"answer":"A","explanation":"By symmetry, x=0 and x=4 are equidistant from vertex x=2. f(4)=f(0)=5.","difficulty":"medium"},{"id":"test_3_math2_q14","module":"math2","questionNumber":14,"type":"stats","skill":"Problem Solving and Data Analysis","passage":"","stem":"Plants: mean height 25 cm, SD 3 cm. How many of 300 plants between 22 and 28 cm (empirical rule)?","choices":["A) 102","B) 150","C) 204","D) 285"],"answer":"C","explanation":"22–28=±1 SD. ~68%. 68%×300=204.","difficulty":"medium"},{"id":"test_3_math2_q15","module":"math2","questionNumber":15,"type":"stats","skill":"Problem Solving and Data Analysis","passage":"","stem":"70% of students use social media, 40% play sports, 25% do both. What percent do neither?","choices":["A) 15%","B) 10%","C) 25%","D) 35%"],"answer":"A","explanation":"At least one = 70 + 40 − 25 = 85. Neither = 100 − 85 = 15%.","difficulty":"medium"},{"id":"test_3_math2_q16","module":"math2","questionNumber":16,"type":"stats","skill":"Problem Solving and Data Analysis","passage":"","stem":"A data set has mean 40 and SD 8. Each value is tripled. What is the new SD?","choices":["A) 8","B) 24","C) 16","D) 120"],"answer":"B","explanation":"Tripling each value triples the SD: 8×3=24.","difficulty":"medium"},{"id":"test_3_math2_q17","module":"math2","questionNumber":17,"type":"stats","skill":"Problem Solving and Data Analysis","passage":"","stem":"Of 100 plants, 60 are treated with fertilizer A, 40 with B. Mean growth with A is 12 cm, with B is 10 cm. What is the overall mean growth?","choices":["A) 10.5","B) 11","C) 11.2","D) 11.5"],"answer":"C","explanation":"(60×12+40×10)/100=(720+400)/100=11.2.","difficulty":"medium"},{"id":"test_3_math2_q18","module":"math2","questionNumber":18,"type":"geometry","skill":"Geometry and Trigonometry","passage":"","stem":"In triangle ABC, AB=9, BC=12, AC=15. What is the area?","choices":["A) 54","B) 60","C) 72","D) 90"],"answer":"A","explanation":"Check: 9²+12²=81+144=225=15². Right triangle. Area=½(9)(12)=54.","difficulty":"medium"},{"id":"test_3_math2_q19","module":"math2","questionNumber":19,"type":"geometry","skill":"Geometry and Trigonometry","passage":"","stem":"A cylinder has volume 54π in³ and height 6 inches. What is the radius?","choices":["A) 4","B) 3","C) 6","D) 9"],"answer":"B","explanation":"54π=πr²(6) → r²=9 → r=3.","difficulty":"medium"},{"id":"test_3_math2_q20","module":"math2","questionNumber":20,"type":"geometry","skill":"Geometry and Trigonometry","passage":"","stem":"sin(θ)=5/13, θ in Q1. What is tan(θ)?","choices":["A) 5/13","B) 12/13","C) 5/12","D) 13/5"],"answer":"C","explanation":"Opposite=5, hyp=13, adjacent=12. tan=5/12.","difficulty":"medium"},{"id":"test_3_math2_q21","module":"math2","questionNumber":21,"type":"gridin","skill":"Advanced Math","passage":"","stem":"If x+y=8 and x²+y²=34, what is xy?","choices":null,"answer":"15","explanation":"(x+y)²=x²+2xy+y² → 64=34+2xy → xy=15.","difficulty":"medium"},{"id":"test_3_math2_q22","module":"math2","questionNumber":22,"type":"gridin","skill":"Problem Solving and Data Analysis","passage":"","stem":"Scores: 70, 75, 80, 85, x. Mean=78. What is the median?","choices":null,"answer":"80","explanation":"310+x=390 → x=80. Ordered: 70,75,80,80,85. Median=80.","difficulty":"medium"}]}},{"id":"test_4","name":"Practice Test 4","description":"Full-length digital SAT practice test","modules":{"rw1":[{"id":"test_4_rw1_q1","module":"rw1","questionNumber":1,"type":"vocab","skill":"Words in Context","passage":"","stem":"The novelist's _____ prose—every word carefully chosen, every sentence precisely constructed—made her work a model of economy in language.","choices":["A) verbose","B) spare","C) flowery","D) rambling"],"answer":"B","explanation":"'Spare' means clean and economical, matching 'every word carefully chosen.' 'Verbose' and 'rambling' are the opposite, 'flowery' means ornate.","difficulty":"easy"},{"id":"test_4_rw1_q2","module":"rw1","questionNumber":2,"type":"vocab","skill":"Words in Context","passage":"","stem":"The CEO's decision to cut research funding proved _____: the company fell behind competitors and eventually filed for bankruptcy.","choices":["A) prudent","B) visionary","C) myopic","D) popular"],"answer":"C","explanation":"'Myopic' means short-sighted, matching 'fell behind competitors and filed for bankruptcy.' 'Prudent' and 'visionary' are positive opposites.","difficulty":"medium"},{"id":"test_4_rw1_q3","module":"rw1","questionNumber":3,"type":"passage","skill":"Command of Evidence","passage":"","stem":"The CEO's decision to cut research funding proved _____: the company fell behind competitors and eventually filed for bankruptcy.","choices":["A) To describe CRISPR's benefits without addressing concerns","B) To argue that CRISPR should be banned","C) To explain the chemistry of DNA editing","D) To present a technology and note both its potential and ethical concerns"],"answer":"D","explanation":"The text presents CRISPR's potential (treatments) and raises ethical concerns (designer babies). Balanced presentation.","difficulty":"easy"},{"id":"test_4_rw1_q4","module":"rw1","questionNumber":4,"type":"transition","skill":"Expression of Ideas","passage":"","stem":"Electric vehicles produce zero direct emissions. _____ the electricity used to charge them may still come from fossil fuel power plants.","choices":["A) However,","B) For example,","C) Consequently,","D) Similarly,"],"answer":"A","explanation":"Zero emissions (positive) vs. fossil fuel electricity (negative). \"However\" signals the contrast.","difficulty":"easy"},{"id":"test_4_rw1_q5","module":"rw1","questionNumber":5,"type":"grammar","skill":"Standard English Conventions","passage":"The company's quarterly earnings, which exceeded analysts' expectations _____ prompted a surge in the stock price.","stem":"Which choice completes the text so that it conforms to the conventions of Standard English?","choices":["A) expectations, which","B) expectations; which","C) expectations, which,","D) expectations—which"],"answer":"C","explanation":"The nonrestrictive clause 'which exceeded analysts' expectations' needs commas on both sides. The clause continues into 'prompted a surge,' so a comma after 'expectations' is needed to close the clause before the main verb.","difficulty":"medium"},{"id":"test_4_rw1_q6","module":"rw1","questionNumber":6,"type":"passage","skill":"Command of Evidence","passage":"","stem":"A 2020 study at the University of British Columbia found that children in nature-based learning programs showed improved attention and reduced stress compared to peers in traditional classrooms. The researchers controlled for socioeconomic factors and prior academic performance.","choices":["A) It argues all schools should adopt nature-based learning.","B) It compares different educational philosophies.","C) It presents findings and describes how researchers accounted for confounding variables.","D) It explains why traditional classrooms are harmful."],"answer":"C","explanation":"Presents findings (improved attention, reduced stress) and notes controls (socioeconomic factors, prior performance).","difficulty":"medium"},{"id":"test_4_rw1_q7","module":"rw1","questionNumber":7,"type":"vocab","skill":"Words in Context","passage":"","stem":"The diplomat's _____ in three languages made her invaluable during international negotiations.","choices":["A) disinterest","B) confusion","C) accent","D) fluency"],"answer":"D","explanation":"'Fluency' means ability to speak easily, matching 'invaluable during negotiations.'","difficulty":"easy"},{"id":"test_4_rw1_q8","module":"rw1","questionNumber":8,"type":"notes","skill":"Rhetorical Synthesis","passage":"","stem":"A student writing about renewable energy has notes:\n- Solar/wind produce no emissions during operation\n- Solar cost decreased 89% since 2010\n- Renewable energy creates more jobs per unit of energy than fossil fuels\n- Wind turbines can harm bird populations\n- Solar farms require large amounts of land\n\nThe student wants to present a balanced view.","choices":["A) While renewable energy creates more jobs and produces no emissions, wind turbines can harm wildlife and solar farms require large amounts of land.","B) Solar and wind produce no emissions.","C) Solar cost decreased 89% since 2010.","D) Renewable energy is always better than fossil fuels."],"answer":"A","explanation":"Presents both benefits (jobs, no emissions) and drawbacks (wildlife harm, land use) for a balanced view.","difficulty":"hard"},{"id":"test_4_rw1_q9","module":"rw1","questionNumber":9,"type":"grammar","skill":"Standard English Conventions","passage":"Three ingredients are essential for the recipe _____ eggs, butter, and flour.","stem":"Which choice completes the text so that it conforms to the conventions of Standard English?","choices":["A) recipe; eggs,","B) recipe: eggs,","C) recipe, eggs,","D) recipe eggs,"],"answer":"B","explanation":"A colon is used after a complete sentence to introduce a list. 'Three ingredients are essential for the recipe' is a complete sentence, so the colon before 'eggs' is correct.","difficulty":"easy"},{"id":"test_4_rw1_q10","module":"rw1","questionNumber":10,"type":"passage","skill":"Text Structure and Purpose","passage":"","stem":"Coral reefs cover less than 1% of the ocean floor but support 25% of marine species. They provide coastal protection, generate tourism revenue, and are a source of medical research compounds. Despite their importance, reefs are declining due to warming, acidification, and pollution.","choices":["A) Pollution is the primary cause of reef decline.","B) Marine species cannot survive without reefs.","C) Coral reefs are important ecosystems that face serious threats.","D) Tourism is destroying reefs."],"answer":"C","explanation":"Establishes importance (biodiversity, protection, revenue) then presents threats. A captures both.","difficulty":"easy"},{"id":"test_4_rw1_q11","module":"rw1","questionNumber":11,"type":"vocab","skill":"Words in Context","passage":"","stem":"The professor's lectures were known for their _____: she had a gift for explaining complex theories in simple language.","choices":["A) ambiguity","B) verbosity","C) monotony","D) clarity"],"answer":"D","explanation":"'Clarity' means clearness, matching 'explaining complex theories in simple language.'","difficulty":"easy"},{"id":"test_4_rw1_q12","module":"rw1","questionNumber":12,"type":"transition","skill":"Expression of Ideas","passage":"","stem":"The city has invested heavily in cycling infrastructure. _____ adoption rates remain low due to inadequate parking facilities for bicycles.","choices":["A) However,","B) For example,","C) Similarly,","D) As a result,"],"answer":"A","explanation":"Investment (positive) vs. low adoption (negative). \"However\" signals the contrast.","difficulty":"medium"},{"id":"test_4_rw1_q13","module":"rw1","questionNumber":13,"type":"passage","skill":"Command of Evidence","passage":"","stem":"Text 1: The rise of plant-based meat represents a significant shift in food technology, potentially reducing the environmental footprint of food production.\n\nText 2: While plant-based meats have gained market share, nutritionists caution that these products are often highly processed and may contain more sodium than animal-based counterparts.","choices":["A) They agree plant-based meat is always healthier.","B) Text 2 acknowledges potential benefits while raising nutritional concerns about Text 1's products.","C) Text 1 criticizes plant-based meat while Text 2 supports it.","D) Both argue consumers should avoid processed foods."],"answer":"B","explanation":"Text 2 acknowledges market share (accepting popularity) but raises nutritional concerns. Acknowledges benefits while adding caveats.","difficulty":"medium"},{"id":"test_4_rw1_q14","module":"rw1","questionNumber":14,"type":"grammar","skill":"Standard English Conventions","passage":"Dr. Patel who specializes in pediatric cardiology _____ will be speaking at the conference next month.","stem":"Which choice completes the text so that it conforms to the conventions of Standard English?","choices":["A) Patel who specializes in pediatric cardiology,","B) Patel, who specializes in pediatric cardiology,","C) Patel who specializes in pediatric cardiology","D) Patel; who specializes in pediatric cardiology,"],"answer":"B","explanation":"The clause 'who specializes in pediatric cardiology' is nonrestrictive (it adds extra info about Dr. Patel) and needs commas on both sides: after 'Patel' and after 'cardiology.'","difficulty":"medium"},{"id":"test_4_rw1_q15","module":"rw1","questionNumber":15,"type":"vocab","skill":"Words in Context","passage":"","stem":"The researcher's _____ analysis—examining every variable and cross-referencing sources—left no room for doubt.","choices":["A) cursory","B) biased","C) speculative","D) meticulous"],"answer":"D","explanation":"'Meticulous' means showing great attention to detail, matching 'examining every variable.'","difficulty":"easy"},{"id":"test_4_rw1_q16","module":"rw1","questionNumber":16,"type":"notes","skill":"Rhetorical Synthesis","passage":"","stem":"A student writing about the discovery of penicillin has notes:\n- 1928: Fleming noticed mold killing bacteria\n- Fleming could not purify the compound\n- 1940: Florey and Chain purified penicillin\n- Mass production during WWII saved countless lives\n- 1945: Nobel Prize shared by all three\n\nThe student wants to emphasize the gap between discovery and medical use.","choices":["A) Fleming could not purify the compound; it was not until 1940 that Florey and Chain successfully purified penicillin for medical use.","B) Fleming discovered penicillin in 1928.","C) Mass production during WWII saved lives.","D) All three shared the 1945 Nobel Prize."],"answer":"A","explanation":"Shows the 12-year gap between discovery (1928) and purification (1940), emphasizing the development needed.","difficulty":"medium"},{"id":"test_4_rw1_q17","module":"rw1","questionNumber":17,"type":"passage","skill":"Command of Evidence","passage":"","stem":"Economist Esther Duflo's research shows that small, targeted interventions can have outsized effects on poverty. Providing free mosquito nets in Kenya increased usage from 20% to 60%, significantly reducing malaria rates. She argues that evidence-based micro-interventions are more effective than broad policy changes.","choices":["A) To describe malaria in Kenya","B) To argue that small, evidence-based interventions can effectively address poverty","C) To compare different public health approaches","D) To explain why broad policies always fail"],"answer":"B","explanation":"Presents Duflo's argument with the net study as evidence. Main purpose is the effectiveness of micro-interventions.","difficulty":"medium"},{"id":"test_4_rw1_q18","module":"rw1","questionNumber":18,"type":"grammar","skill":"Standard English Conventions","passage":"","stem":"The symphony, which _____ composed in 1808, is regarded as one of Beethoven's greatest works.","choices":["A) were","B) is","C) was","D) has been"],"answer":"C","explanation":"Past tense \"was\" matches \"composed in 1808\" (completed past event). \"Were\" is plural, \"is\" is present.","difficulty":"easy"},{"id":"test_4_rw1_q19","module":"rw1","questionNumber":19,"type":"vocab","skill":"Words in Context","passage":"","stem":"The senator's speech was filled with _____ rhetoric—stirring imagery that moved the audience but offered little concrete policy.","choices":["A) vapid","B) hostile","C) technical","D) eloquent"],"answer":"D","explanation":"'Eloquent' means fluent and persuasive, matching 'stirring imagery.' The contrast with 'little concrete policy' suggests style over substance.","difficulty":"medium"},{"id":"test_4_rw1_q20","module":"rw1","questionNumber":20,"type":"passage","skill":"Command of Evidence","passage":"","stem":"In 2016, Barcelona implemented \"superblocks,\" converting car-filled streets into pedestrian plazas. Studies found noise pollution dropped 25% and NO2 levels decreased significantly in affected areas.","choices":["A) To describe a city planning initiative and its measured outcomes","B) To argue all cities should adopt superblocks","C) To compare Barcelona with other cities","D) To explain why car ownership is declining"],"answer":"A","explanation":"Describes the program and presents measured outcomes (noise, NO2).","difficulty":"easy"},{"id":"test_4_rw1_q21","module":"rw1","questionNumber":21,"type":"transition","skill":"Expression of Ideas","passage":"","stem":"Archaeologists believed humans arrived in the Americas 13,000 years ago via a land bridge. _____ discoveries of 16,000-year-old tools in Chile suggest earlier arrival, possibly by coastal routes.","choices":["A) Similarly,","B) However,","C) For example,","D) Therefore,"],"answer":"B","explanation":"Established timeline vs. new evidence. \"However\" signals the contrast.","difficulty":"easy"},{"id":"test_4_rw1_q22","module":"rw1","questionNumber":22,"type":"grammar","skill":"Standard English Conventions","passage":"","stem":"The new policy, _____ aims to reduce emissions by 40%, has been endorsed by environmental groups.","choices":["A) that","B) what","C) which","D) it"],"answer":"C","explanation":"Nonrestrictive clause (commas). \"Which\" is correct for nonrestrictive clauses modifying things.","difficulty":"medium"},{"id":"test_4_rw1_q23","module":"rw1","questionNumber":23,"type":"notes","skill":"Rhetorical Synthesis","passage":"","stem":"A student writing about sleep deprivation has notes:\n- Adults need 7-9 hours per night\n- Sleep deprivation impairs cognition similar to alcohol\n- Chronic deprivation linked to obesity, diabetes, cardiovascular disease\n- 1 in 3 American adults doesn't get enough sleep\n- Shift workers are disproportionately affected\n\nThe student wants to emphasize the scale of the problem.","choices":["A) Adults need 7-9 hours of sleep.","B) Shift workers are disproportionately affected.","C) Sleep deprivation impairs cognition like alcohol.","D) 1 in 3 American adults doesn't get enough sleep, and chronic deprivation is linked to obesity, diabetes, and cardiovascular disease."],"answer":"D","explanation":"Combines prevalence (1 in 3) with serious health consequences, emphasizing the scale.","difficulty":"medium"},{"id":"test_4_rw1_q24","module":"rw1","questionNumber":24,"type":"vocab","skill":"Words in Context","passage":"","stem":"The chef's _____ approach—combining unexpected ingredients like chocolate and chili—initially surprised diners but won critical acclaim.","choices":["A) conventional","B) unorthodox","C) careless","D) traditional"],"answer":"B","explanation":"'Unorthodox' means unconventional, matching 'unexpected ingredients' and initial surprise.","difficulty":"easy"},{"id":"test_4_rw1_q25","module":"rw1","questionNumber":25,"type":"passage","skill":"Command of Evidence","passage":"","stem":"A 2022 study found that handwriting notes retains more information than typing. Researchers attributed this to handwriting forcing students to process and summarize rather than transcribe verbatim.","choices":["A) Laptop note-taking is always inferior.","B) Handwriting may improve retention because it requires active processing.","C) Students should never use laptops.","D) The journal published a controversial study."],"answer":"B","explanation":"Presents the finding (handwriting retains more) and the mechanism (active processing vs. transcription).","difficulty":"easy"},{"id":"test_4_rw1_q26","module":"rw1","questionNumber":26,"type":"grammar","skill":"Standard English Conventions","passage":"","stem":"The team of researchers _____ been working on the vaccine for two years before achieving a breakthrough.","choices":["A) has","B) have","C) had","D) having"],"answer":"C","explanation":"Past perfect \"had been working\" shows action completed before another past action (\"achieving\").","difficulty":"medium"},{"id":"test_4_rw1_q27","module":"rw1","questionNumber":27,"type":"passage","skill":"Text Structure and Purpose","passage":"","stem":"The concept of \"food miles\"—the distance food travels from farm to plate—has been used to argue that local food is more environmentally friendly. However, a 2020 study found transportation accounts for only 10% of food's carbon footprint, while production methods account for over 80%.","choices":["A) It supports the food miles concept.","B) It challenges the food miles concept by showing transportation is a relatively small factor.","C) It explains why local food is always better.","D) It defines carbon footprint."],"answer":"B","explanation":"The data (10% vs. 80%) challenges the food miles concept that focuses on distance.","difficulty":"medium"}],"rw2":[{"id":"test_4_rw2_q1","module":"rw2","questionNumber":1,"type":"grammar","skill":"Standard English Conventions","passage":"The company's quarterly earnings, which exceeded analysts' expectations _____ prompted a surge in the stock price.","stem":"Which choice completes the text so that it conforms to the conventions of Standard English?","choices":["A) expectations, which","B) expectations; which","C) expectations, which,","D) expectations—which"],"answer":"C","explanation":"The nonrestrictive clause 'which exceeded analysts' expectations' needs commas on both sides. The clause continues into 'prompted a surge,' so a comma after 'expectations' is needed to close the clause before the main verb.","difficulty":"medium"},{"id":"test_4_rw2_q2","module":"rw2","questionNumber":2,"type":"passage","skill":"Command of Evidence","passage":"","stem":"Social media use is correlated with increased anxiety and depression in teenagers. However, researchers caution that correlation does not imply causation—teenagers with existing mental health issues may be more likely to use social media extensively.","choices":["A) To prove social media causes mental health problems","B) To argue teenagers should stop using social media","C) To present a correlation while noting that causation has not been established","D) To explain how platforms are designed"],"answer":"C","explanation":"Presents the correlation but explicitly cautions against assuming causation. B captures both the finding and the caveat.","difficulty":"medium"},{"id":"test_4_rw2_q3","module":"rw2","questionNumber":3,"type":"transition","skill":"Expression of Ideas","passage":"","stem":"The Great Barrier Reef has experienced five mass bleaching events since 2016. _____ scientists warn that without reduced emissions, the reef could face annual bleaching by 2050.","choices":["A) For example,","B) In other words,","C) As a result,","D) Looking ahead,"],"answer":"D","explanation":"Past events vs. future projections. \"Looking ahead\" signals the temporal shift to predictions.","difficulty":"medium"},{"id":"test_4_rw2_q4","module":"rw2","questionNumber":4,"type":"vocab","skill":"Words in Context","passage":"","stem":"The politician's _____ promises—offering everything from free healthcare to universal basic income—sounded appealing but lacked implementation plans.","choices":["A) sweeping","B) modest","C) vague","D) honest"],"answer":"A","explanation":"'Sweeping' means broad and far-reaching, matching the range of promises. The contrast with 'lacking plans' suggests scope over substance.","difficulty":"medium"},{"id":"test_4_rw2_q5","module":"rw2","questionNumber":5,"type":"grammar","skill":"Standard English Conventions","passage":"Three ingredients are essential for the recipe _____ eggs, butter, and flour.","stem":"Which choice completes the text so that it conforms to the conventions of Standard English?","choices":["A) recipe; eggs,","B) recipe: eggs,","C) recipe, eggs,","D) recipe eggs,"],"answer":"B","explanation":"A colon is used after a complete sentence to introduce a list. 'Three ingredients are essential for the recipe' is a complete sentence, so the colon before 'eggs' is correct.","difficulty":"easy"},{"id":"test_4_rw2_q6","module":"rw2","questionNumber":6,"type":"passage","skill":"Command of Evidence","passage":"","stem":"A 2021 study found that people who regularly play instruments have thicker cortical regions associated with auditory processing. The effects were most pronounced in those who began playing before age seven.","choices":["A) It provides additional detail refining the finding.","B) It contradicts the study.","C) It introduces a separate study.","D) It explains methodology."],"answer":"A","explanation":"Adds nuance: strongest effect in early starters, refining the main finding.","difficulty":"medium"},{"id":"test_4_rw2_q7","module":"rw2","questionNumber":7,"type":"notes","skill":"Rhetorical Synthesis","passage":"","stem":"A student researching bilingualism has notes:\n- Bilingual children show enhanced executive function\n- Speaking two languages may delay dementia by 4-5 years\n- Bilingual individuals are better at multitasking\n- Learning a second language improves understanding of one's native language\n- Bilingual people may earn higher salaries\n\nThe student wants to emphasize cognitive benefits.","choices":["A) Bilingual people may earn higher salaries.","B) Learning a second language improves native language understanding.","C) Speaking two languages may delay dementia.","D) Bilingual children show enhanced executive function, and bilingual individuals tend to be better at multitasking."],"answer":"D","explanation":"Combines two cognitive benefits (executive function, multitasking), directly addressing the goal.","difficulty":"medium"},{"id":"test_4_rw2_q8","module":"rw2","questionNumber":8,"type":"passage","skill":"Command of Evidence","passage":"","stem":"A 2021 study found that global tree canopy increased by 2.24 million sq km since 1982. However, much of this increase is due to tree plantations, which support far less biodiversity than natural forests.","choices":["A) Natural forests are being replaced by plantations.","B) While tree cover has increased globally, much of the gain lacks biodiversity of natural forests.","C) Tree plantations are better than natural forests.","D) The global canopy has decreased since 1982."],"answer":"B","explanation":"Presents the increase but qualifies it with the biodiversity concern. B captures both.","difficulty":"medium"},{"id":"test_4_rw2_q9","module":"rw2","questionNumber":9,"type":"passage","skill":"Command of Evidence","passage":"","stem":"Herbert Simon coined \"satisficing\"—choosing the first option meeting minimum criteria rather than searching for the optimal choice. Research shows satisficers tend to be happier than maximizers.","choices":["A) Why satisficing is flawed.","B) Definitions of key terms.","C) Research methods used.","D) A counterintuitive finding supporting satisficing."],"answer":"D","explanation":"The finding that satisficers are happier is counterintuitive and supports satisficing.","difficulty":"hard"},{"id":"test_4_rw2_q10","module":"rw2","questionNumber":10,"type":"vocab","skill":"Words in Context","passage":"","stem":"The critic described the novel as _____: the plot was inventive but the characters felt flat.","choices":["A) uneven","B) masterful","C) boring","D) original"],"answer":"A","explanation":"'Uneven' means inconsistent, matching inventive plot vs. flat characters.","difficulty":"medium"},{"id":"test_4_rw2_q11","module":"rw2","questionNumber":11,"type":"grammar","skill":"Standard English Conventions","passage":"Dr. Patel who specializes in pediatric cardiology _____ will be speaking at the conference next month.","stem":"Which choice completes the text so that it conforms to the conventions of Standard English?","choices":["A) Patel who specializes in pediatric cardiology,","B) Patel, who specializes in pediatric cardiology,","C) Patel who specializes in pediatric cardiology","D) Patel; who specializes in pediatric cardiology,"],"answer":"B","explanation":"The clause 'who specializes in pediatric cardiology' is nonrestrictive (it adds extra info about Dr. Patel) and needs commas on both sides: after 'Patel' and after 'cardiology.'","difficulty":"medium"},{"id":"test_4_rw2_q12","module":"rw2","questionNumber":12,"type":"passage","skill":"Command of Evidence","passage":"","stem":"Economists debate the relationship between minimum wage and employment. Traditional theory suggests raising wages leads to job losses. However, a 1994 study by Card and Krueger found that a minimum wage increase in New Jersey did not lead to significant job losses compared to Pennsylvania.","choices":["A) It argues minimum wage increases always cause job losses.","B) It compares NJ and PA economies.","C) It presents a theoretical prediction and describes evidence challenging it.","D) It explains why traditional theory is always correct."],"answer":"C","explanation":"Presents theory (wages → job losses) then describes empirical evidence challenging it (Card-Krueger study).","difficulty":"medium"},{"id":"test_4_rw2_q13","module":"rw2","questionNumber":13,"type":"notes","skill":"Rhetorical Synthesis","passage":"","stem":"A student researching coffee and health has notes:\n- 3-4 cups/day associated with 15% lower cardiovascular disease risk\n- Caffeine temporarily increases blood pressure\n- Coffee contains antioxidants that may reduce inflammation\n- Over 6 cups/day may increase anxiety and disrupt sleep\n- Pregnant women should limit caffeine\n\nThe student wants to emphasize benefits of moderate consumption.","choices":["A) Caffeine increases blood pressure.","B) Excessive coffee may increase anxiety.","C) Pregnant women should limit caffeine.","D) Drinking 3-4 cups daily is associated with 15% lower cardiovascular risk, and coffee contains antioxidants that may reduce inflammation."],"answer":"D","explanation":"Combines cardiovascular benefit (moderate) with antioxidant benefit, addressing moderate consumption.","difficulty":"medium"},{"id":"test_4_rw2_q14","module":"rw2","questionNumber":14,"type":"grammar","skill":"Standard English Conventions","passage":"","stem":"The ancient manuscript, _____ origin remains a mystery, was discovered in a cave in Afghanistan.","choices":["A) its","B) whose","C) it's","D) which"],"answer":"B","explanation":"'Whose' is the possessive relative pronoun connecting 'manuscript' to 'origin.'","difficulty":"medium"},{"id":"test_4_rw2_q15","module":"rw2","questionNumber":15,"type":"transition","skill":"Expression of Ideas","passage":"","stem":"Solar energy has become increasingly affordable. The cost of solar panels has dropped 70% since 2010. _____ adoption rates remain low in many regions due to inadequate grid infrastructure.","choices":["A) For example,","B) Similarly,","C) Nevertheless,","D) As a result,"],"answer":"C","explanation":"Lower costs (positive) vs. low adoption (negative). \"Nevertheless\" signals the contrast.","difficulty":"medium"},{"id":"test_4_rw2_q16","module":"rw2","questionNumber":16,"type":"vocab","skill":"Words in Context","passage":"","stem":"The speaker's _____ about the economy—acknowledging both strengths and weaknesses—was refreshing compared to the usual partisan rhetoric.","choices":["A) bias","B) candor","C) confusion","D) hostility"],"answer":"B","explanation":"'Candor' means honest and straightforward, matching 'acknowledging both strengths and weaknesses.'","difficulty":"medium"},{"id":"test_4_rw2_q17","module":"rw2","questionNumber":17,"type":"notes","skill":"Rhetorical Synthesis","passage":"","stem":"A student researching the internet has notes:\n- 1969: ARPANET connected four university computers\n- 1983: TCP/IP protocol adopted\n- 1991: Tim Berners-Lee created the World Wide Web\n- 1993: Mosaic browser introduced graphical interface\n- 2007: iPhone accelerated mobile internet\n\nThe student wants to highlight how the internet became accessible to the public.","choices":["A) ARPANET connected four computers in 1969.","B) TCP/IP was adopted in 1983.","C) Tim Berners-Lee created the WWW in 1991, and the Mosaic browser in 1993 introduced a graphical interface, making the internet accessible to non-specialists.","D) The iPhone was released in 2007."],"answer":"C","explanation":"Combines WWW creation (accessible to non-specialists) and graphical browser (easy to use), showing how the internet became public.","difficulty":"medium"},{"id":"test_4_rw2_q18","module":"rw2","questionNumber":18,"type":"grammar","skill":"Standard English Conventions","passage":"","stem":"The architect _____ designed the building won several international awards for innovative use of sustainable materials.","choices":["A) which","B) whose","C) who","D) she"],"answer":"C","explanation":"'Who' introduces a relative clause modifying 'architect' (a person).","difficulty":"easy"},{"id":"test_4_rw2_q19","module":"rw2","questionNumber":19,"type":"vocab","skill":"Words in Context","passage":"","stem":"The speaker's _____ delivery—pausing for effect, varying tone, making eye contact—kept the audience engaged for two hours.","choices":["A) dynamic","B) monotone","C) rushed","D) hesitant"],"answer":"A","explanation":"'Dynamic' means energetic and engaging, matching the techniques described.","difficulty":"easy"},{"id":"test_4_rw2_q20","module":"rw2","questionNumber":20,"type":"passage","skill":"Command of Evidence","passage":"","stem":"The concept of \"degrowth\" challenges the assumption that economic growth is always desirable. Proponents argue that in wealthy nations, GDP growth does not necessarily improve well-being and may accelerate environmental destruction. They advocate prioritizing sustainability and quality of life.","choices":["A) To define degrowth and explain its core arguments","B) To argue GDP is the best measure of success","C) To compare degrowth with other theories","D) To explain why wealthy nations should stop growing"],"answer":"A","explanation":"Defines degrowth, presents arguments (GDP ≠ well-being, environmental harm), and advocacy.","difficulty":"easy"},{"id":"test_4_rw2_q21","module":"rw2","questionNumber":21,"type":"vocab","skill":"Words in Context","passage":"","stem":"The novelist's _____ descriptions—capturing smells, sounds, and textures of rural life—transported readers far from their urban existences.","choices":["A) perfunctory","B) evocative","C) technical","D) somber"],"answer":"B","explanation":"'Evocative' means vivid and powerful, matching sensory details that transport readers.","difficulty":"easy"},{"id":"test_4_rw2_q22","module":"rw2","questionNumber":22,"type":"grammar","skill":"Standard English Conventions","passage":"","stem":"The teacher asked the students to submit _____ assignments by Friday.","choices":["A) there","B) their","C) they're","D) they"],"answer":"B","explanation":"'Their' is the possessive form of 'they,' modifying 'assignments.'","difficulty":"easy"},{"id":"test_4_rw2_q23","module":"rw2","questionNumber":23,"type":"passage","skill":"Text Structure and Purpose","passage":"","stem":"Astronomers have discovered thousands of exoplanets. A small number orbit in the habitable zone where liquid water could potentially exist on the surface.","choices":["A) All exoplanets are inhospitable.","B) Among thousands of discovered exoplanets, a small fraction orbit in conditions that could support liquid water.","C) Astronomers have found life on exoplanets.","D) The habitable zone is the only factor for life."],"answer":"B","explanation":"Presents two facts: thousands discovered, small fraction in habitable zone. B captures both.","difficulty":"easy"},{"id":"test_4_rw2_q24","module":"rw2","questionNumber":24,"type":"grammar","skill":"Standard English Conventions","passage":"","stem":"Among all the students in the advanced class, Priya has demonstrated the _____ understanding of organic chemistry.","choices":["A) strong","B) stronger","C) strongest","D) most strong"],"answer":"C","explanation":"\"Among all\" compares three or more, requiring superlative \"strongest.\"","difficulty":"easy"},{"id":"test_4_rw2_q25","module":"rw2","questionNumber":25,"type":"passage","skill":"Command of Evidence","passage":"","stem":"A 2023 study found that urban green spaces are associated with lower rates of depression and anxiety. The effect was strongest in low-income neighborhoods, suggesting green spaces may help reduce health disparities.","choices":["A) Urban green spaces are associated with improved mental health, particularly in low-income areas.","B) All neighborhoods should have equal green space.","C) Depression is caused by lack of green space.","D) Low-income neighborhoods have the most parks."],"answer":"A","explanation":"Presents two findings: green spaces improve mental health, and the effect is strongest in low-income areas.","difficulty":"easy"},{"id":"test_4_rw2_q26","module":"rw2","questionNumber":26,"type":"grammar","skill":"Standard English Conventions","passage":"","stem":"The number of students in online courses _____ dramatically since the pandemic.","choices":["A) increase","B) increases","C) has increased","D) increasing"],"answer":"C","explanation":"\"Since the pandemic\" continues to present. Present perfect \"has increased.\"","difficulty":"easy"},{"id":"test_4_rw2_q27","module":"rw2","questionNumber":27,"type":"passage","skill":"Command of Evidence","passage":"","stem":"Psychologist Angela Duckworth's research on \"grit\"—passion and perseverance for long-term goals—shows that grit predicts success better than IQ or talent. In studies of West Point cadets and spelling bee contestants, grittier individuals were more likely to achieve their goals.","choices":["A) IQ is the most important predictor of success.","B) Grit, or sustained passion and perseverance, can be a stronger predictor of success than innate ability.","C) West Point cadets are grittier than spelling bee contestants.","D) Talent is irrelevant to achieving goals."],"answer":"B","explanation":"Presents Duckworth's finding that grit predicts success better than IQ or talent, with evidence from multiple domains.","difficulty":"easy"}],"math1":[{"id":"test_4_math1_q1","module":"math1","questionNumber":1,"type":"algebra","skill":"Algebra","passage":"","stem":"If 5x − 3 = 2x + 15, what is x?","choices":["A) 3","B) 6","C) 5","D) 9"],"answer":"B","explanation":"3x=18, x=6. Check: 30−3=27, 12+15=27 ✓.","difficulty":"easy"},{"id":"test_4_math1_q2","module":"math1","questionNumber":2,"type":"algebra","skill":"Algebra","passage":"","stem":"A coffee shop sells small coffees for $3 and large coffees for $5. In one hour, 40 coffees were sold for $148. How many large coffees?","choices":["A) 10","B) 12","C) 14","D) 16"],"answer":"C","explanation":"s+l=40, 3s+5l=148. 3(40−l)+5l=148 → 120+2l=148 → l=14.","difficulty":"medium"},{"id":"test_4_math1_q3","module":"math1","questionNumber":3,"type":"algebra","skill":"Algebra","passage":"","stem":"If f(x) = (4x + 8)/2, which is equivalent?","choices":["A) 2x + 8","B) 4x + 4","C) x + 4","D) 2x + 4"],"answer":"D","explanation":"(4x+8)/2=2x+4.","difficulty":"easy"},{"id":"test_4_math1_q4","module":"math1","questionNumber":4,"type":"algebra","skill":"Algebra","passage":"","stem":"The graph of y=f(x) passes through (1, 7) and (5, 19). If f is linear, what is the slope?","choices":["A) 3","B) 2","C) 4","D) 6"],"answer":"A","explanation":"Slope=(19−7)/(5−1)=12/4=3.","difficulty":"easy"},{"id":"test_4_math1_q5","module":"math1","questionNumber":5,"type":"algebra","skill":"Algebra","passage":"","stem":"A worker earns $22/hr and time-and-a-half over 8 hours. If the worker earned $308 in one day, how many hours did they work?","choices":["A) 10","B) 12","C) 11","D) 13"],"answer":"B","explanation":"8(22)=176. OT rate=33. (308−176)/33=132/33=4. Total=8+4=12.","difficulty":"medium"},{"id":"test_4_math1_q6","module":"math1","questionNumber":6,"type":"algebra","skill":"Algebra","passage":"","stem":"A stock decreased 15% in January, then increased 20% in February. Net change?","choices":["A) −8%","B) +5%","C) +2%","D) +8%"],"answer":"C","explanation":"0.85P×1.20=1.02P. Net +2%.","difficulty":"hard"},{"id":"test_4_math1_q7","module":"math1","questionNumber":7,"type":"algebra","skill":"Advanced Math","passage":"","stem":"Which is a factor of x³+27?","choices":["A) x−3","B) x+9","C) x²+9","D) x+3"],"answer":"D","explanation":"Sum of cubes: x³+3³=(x+3)(x²−3x+9). (x+3) is a factor.","difficulty":"medium"},{"id":"test_4_math1_q8","module":"math1","questionNumber":8,"type":"algebra","skill":"Advanced Math","passage":"","stem":"f(x)=3x²−12x+7. Which form shows the minimum value?","choices":["A) f(x)=3(x−2)²−5","B) f(x)=3(x−2)²+7","C) f(x)=3(x+2)²−5","D) f(x)=(3x−6)(x−2)+1"],"answer":"A","explanation":"3(x²−4x)+7=3(x−2)²−12+7=3(x−2)²−5. Min=−5.","difficulty":"medium"},{"id":"test_4_math1_q9","module":"math1","questionNumber":9,"type":"algebra","skill":"Advanced Math","passage":"","stem":"If x+1/x=4, what is x²+1/x²?","choices":["A) 12","B) 14","C) 16","D) 18"],"answer":"B","explanation":"Square: x²+2+1/x²=16. x²+1/x²=14.","difficulty":"hard"},{"id":"test_4_math1_q10","module":"math1","questionNumber":10,"type":"algebra","skill":"Advanced Math","passage":"","stem":"h(x) has zeros at x=−1, 3, 5 and h(0)=30. Which defines h(x)?","choices":["A) h(x)=(x+1)(x−3)(x−5)","B) h(x)=−2(x+1)(x−3)(x−5)","C) h(x)=2(x+1)(x−3)(x−5)","D) h(x)=(x−1)(x+3)(x+5)"],"answer":"C","explanation":"h(0)=a(1)(−3)(−5)=15a=30 → a=2. h(x)=2(x+1)(x−3)(x−5).","difficulty":"medium"},{"id":"test_4_math1_q11","module":"math1","questionNumber":11,"type":"algebra","skill":"Advanced Math","passage":"","stem":"If 2^(x+1)=8^(x−1), what is x?","choices":["A) 1","B) 3","C) 4","D) 2"],"answer":"D","explanation":"2^(x+1)=2^(3x−3). x+1=3x−3 → 4=2x → x=2.","difficulty":"medium"},{"id":"test_4_math1_q12","module":"math1","questionNumber":12,"type":"algebra","skill":"Advanced Math","passage":"","stem":"For what k does x²+kx+9=0 have two equal real solutions?","choices":["A) −6","B) −3","C) 3","D) 6"],"answer":"A","explanation":"Discriminant=0: k²−36=0 → k=±6. Answer includes −6.","difficulty":"medium"},{"id":"test_4_math1_q13","module":"math1","questionNumber":13,"type":"algebra","skill":"Advanced Math","passage":"","stem":"If 27^x=9, what is x?","choices":["A) 1/3","B) 2/3","C) 3/2","D) 2"],"answer":"B","explanation":"27^x=3^(3x)=9=3². 3x=2, x=2/3.","difficulty":"medium"},{"id":"test_4_math1_q14","module":"math1","questionNumber":14,"type":"algebra","skill":"Advanced Math","passage":"","stem":"The vertex of y=−(x+5)²+12 is:","choices":["A) (5, 12)","B) (5, −12)","C) (−5, 12)","D) (−5, −12)"],"answer":"C","explanation":"Vertex form: vertex=(−5, 12).","difficulty":"easy"},{"id":"test_4_math1_q15","module":"math1","questionNumber":15,"type":"stats","skill":"Problem Solving and Data Analysis","passage":"","stem":"In a class of 30 students, 18 play sports and 12 play music. If 5 play both, how many play neither?","choices":["A) 3","B) 7","C) 10","D) 5"],"answer":"D","explanation":"At least one=18+12−5=25. Neither=30−5=5.","difficulty":"medium"},{"id":"test_4_math1_q16","module":"math1","questionNumber":16,"type":"stats","skill":"Problem Solving and Data Analysis","passage":"","stem":"Data: 3, 5, 5, 7, 8, 10. What is the mean?","choices":["A) 6.33","B) 5","C) 6","D) 7"],"answer":"A","explanation":"Mean=(3+5+5+7+8+10)/6=38/6=6.33.","difficulty":"easy"},{"id":"test_4_math1_q17","module":"math1","questionNumber":17,"type":"stats","skill":"Problem Solving and Data Analysis","passage":"","stem":"A company has a 4% defect rate. Producing 1,500 items per day, how many defective per week (7 days)?","choices":["A) 60","B) 420","C) 600","D) 840"],"answer":"B","explanation":"4%×1,500=60 per day. 60×7=420 per week.","difficulty":"medium"},{"id":"test_4_math1_q18","module":"math1","questionNumber":18,"type":"stats","skill":"Problem Solving and Data Analysis","passage":"","stem":"A model predicts score=2.5(hours)+55. How many hours for a score of 80?","choices":["A) 5","B) 8","C) 10","D) 15"],"answer":"C","explanation":"80=2.5h+55 → 2.5h=25 → h=10.","difficulty":"easy"},{"id":"test_4_math1_q19","module":"math1","questionNumber":19,"type":"stats","skill":"Problem Solving and Data Analysis","passage":"","stem":"A scatterplot shows r=−0.85 between screen time and sleep quality. Best interpretation?","choices":["A) More screen time causes worse sleep.","B) 85% of sleep variation is explained by screen time.","C) Screen time has no effect on sleep.","D) There is a strong negative linear association between screen time and sleep quality."],"answer":"D","explanation":"r=−0.85 indicates strong negative association. A confuses correlation with causation, C confuses r with r².","difficulty":"medium"},{"id":"test_4_math1_q20","module":"math1","questionNumber":20,"type":"geometry","skill":"Geometry and Trigonometry","passage":"","stem":"A circle has center (−1, 3) and passes through (2, 7). What is the radius?","choices":["A) 5","B) 3","C) 4","D) 7"],"answer":"A","explanation":"Distance=√((2+1)²+(7−3)²)=√(9+16)=5.","difficulty":"medium"},{"id":"test_4_math1_q21","module":"math1","questionNumber":21,"type":"geometry","skill":"Geometry and Trigonometry","passage":"","stem":"A rectangular pool is 3 times as long as it is wide. If the perimeter is 80 meters, what is the area?","choices":["A) 200","B) 300","C) 400","D) 600"],"answer":"B","explanation":"w, l=3w. 8w=80 → w=10, l=30. Area=300.","difficulty":"medium"},{"id":"test_4_math1_q22","module":"math1","questionNumber":22,"type":"geometry","skill":"Geometry and Trigonometry","passage":"","stem":"A cone has radius 8 cm and slant height 17 cm. What is the total surface area?","choices":["A) 64π","B) 136π","C) 200π","D) 288π"],"answer":"C","explanation":"SA=πr²+πrl=64π+136π=200π.","difficulty":"medium"}],"math2":[{"id":"test_4_math2_q1","module":"math2","questionNumber":1,"type":"algebra","skill":"Algebra","passage":"","stem":"A boat travels 60 miles downstream in 3 hours and returns upstream in 5 hours. What is the speed of the current?","choices":["A) 2 mph","B) 4 mph","C) 6 mph","D) 8 mph"],"answer":"B","explanation":"Downstream speed=20 mph. Upstream speed=12 mph. Boat speed=(20+12)/2=16. Current=(20−12)/2=4.","difficulty":"hard"},{"id":"test_4_math2_q2","module":"math2","questionNumber":2,"type":"algebra","skill":"Algebra","passage":"","stem":"A store offers 20% off, then an additional 15% off the discounted price. What is the total discount?","choices":["A) 30%","B) 35%","C) 38%","D) 32%"],"answer":"D","explanation":"After 20% off: 0.80P. After 15% more: 0.80×0.85=0.68P. Discount=32%.","difficulty":"hard"},{"id":"test_4_math2_q3","module":"math2","questionNumber":3,"type":"algebra","skill":"Algebra","passage":"","stem":"A train leaves at 8 AM at 50 mph. Another leaves the same station at 10 AM at 80 mph same direction. When does the second catch the first?","choices":["A) 1:20 PM","B) 12:00 PM","C) 12:40 PM","D) 1:00 PM"],"answer":"A","explanation":"At 10 AM, train 1 is 100 miles ahead. Closing rate=30 mph. Time=100/30=3.33 hours=3h20min after 10 AM=1:20 PM.","difficulty":"hard"},{"id":"test_4_math2_q4","module":"math2","questionNumber":4,"type":"algebra","skill":"Algebra","passage":"","stem":"A chemist mixes 12 liters of 25% acid with x liters of 60% acid to get 50% acid. How many liters of 60% solution?","choices":["A) 12","B) 15","C) 18","D) 20"],"answer":"B","explanation":"0.25(12)+0.60x=0.50(12+x) → 3+0.6x=6+0.4x → 0.2x=3 → x=15.","difficulty":"hard"},{"id":"test_4_math2_q5","module":"math2","questionNumber":5,"type":"algebra","skill":"Advanced Math","passage":"","stem":"If log(x−1)+log(x+1)=log(8), what is x?","choices":["A) 2","B) 4","C) 3","D) 8"],"answer":"C","explanation":"(x−1)(x+1)=8 → x²−1=8 → x²=9 → x=3 (positive).","difficulty":"hard"},{"id":"test_4_math2_q6","module":"math2","questionNumber":6,"type":"algebra","skill":"Advanced Math","passage":"","stem":"f(x)=ax²+bx+c passes through (0,3), (−1,6), and (2,3). What is f(1)?","choices":["A) 1","B) 3","C) 4","D) 2"],"answer":"D","explanation":"c=3 from f(0). f(−1)=a−b+3=6 → a−b=3. f(2)=4a+2b+3=3 → 4a+2b=0 → 2a+b=0. Add with a−b=3: 3a=3 → a=1, b=−2. f(1)=1−2+3=2.","difficulty":"hard"},{"id":"test_4_math2_q7","module":"math2","questionNumber":7,"type":"algebra","skill":"Advanced Math","passage":"","stem":"If 5^(x+1)−5^x=100, what is 5^x?","choices":["A) 25","B) 5","C) 10","D) 20"],"answer":"A","explanation":"5³5^x−5^x=100 → 4³5^x=100 → 5^x=25.","difficulty":"hard"},{"id":"test_4_math2_q8","module":"math2","questionNumber":8,"type":"stats","skill":"Problem Solving and Data Analysis","passage":"","stem":"A data set has mean 60 and SD 12. Each value is halved, then 10 is subtracted. What is the new SD?","choices":["A) 6","B) 4","C) 12","D) 22"],"answer":"A","explanation":"Halving: SD=6. Subtracting constant: SD unchanged=6.","difficulty":"hard"},{"id":"test_4_math2_q9","module":"math2","questionNumber":9,"type":"geometry","skill":"Geometry and Trigonometry","passage":"","stem":"Line perpendicular to 4x−3y=12 passes through (4, 3). What is the y-intercept?","choices":["A) −4","B) −2","C) 2","D) 6"],"answer":"D","explanation":"Slope of 4x−3y=12 is 4/3. Perpendicular slope = −3/4. Using (4,3): 3 = (−3/4)(4) + b → 3 = −3 + b → b = 6.","difficulty":"hard"},{"id":"test_4_math2_q10","module":"math2","questionNumber":10,"type":"gridin","skill":"Algebra","passage":"","stem":"Mix 6 liters of 15% acid with x liters of 45% acid to get 25% acid. How many liters of 45%?","choices":null,"answer":"3","explanation":"0.9+0.45x=1.5+0.25x → 0.2x=0.6 → x=3.","difficulty":"hard"},{"id":"test_4_math2_q11","module":"math2","questionNumber":11,"type":"algebra","skill":"Advanced Math","passage":"","stem":"Sequence: a₁=5, aₙ=2aₙ₋₁−3. What is a₄?","choices":["A) 11","B) 13","C) 19","D) 25"],"answer":"C","explanation":"5, 7, 11, 19. a₄=2(11)−3=19.","difficulty":"medium"},{"id":"test_4_math2_q12","module":"math2","questionNumber":12,"type":"algebra","skill":"Advanced Math","passage":"","stem":"A parabola has vertex (4, 1) and passes through (2, 5). What is f(6)?","choices":["A) 1","B) 3","C) 9","D) 5"],"answer":"D","explanation":"By symmetry, x=2 and x=6 are equidistant from vertex x=4. f(6)=f(2)=5.","difficulty":"medium"},{"id":"test_4_math2_q13","module":"math2","questionNumber":13,"type":"stats","skill":"Problem Solving and Data Analysis","passage":"","stem":"A study of 400 plants: mean 28 cm, SD 5 cm. How many between 23 and 33 cm (empirical rule)?","choices":["A) 136","B) 272","C) 200","D) 380"],"answer":"B","explanation":"23–33=28±5=±1 SD. ~68%. 68%×400=272.","difficulty":"medium"},{"id":"test_4_math2_q14","module":"math2","questionNumber":14,"type":"stats","skill":"Problem Solving and Data Analysis","passage":"","stem":"A game costs $3. Roll a die: win $12 on 6, win $3 on 4-5, nothing 1-3. Expected net gain?","choices":["A) −$0.50","B) $0.50","C) $0","D) $1.00"],"answer":"C","explanation":"Expected=(1/6)(12)+(2/6)(3)=2+1=$3. Net=3−3=$0.","difficulty":"medium"},{"id":"test_4_math2_q15","module":"math2","questionNumber":15,"type":"stats","skill":"Problem Solving and Data Analysis","passage":"","stem":"50% exercise regularly, 30% meditate, 15% do both. What percent do at least one?","choices":["A) 55%","B) 75%","C) 80%","D) 65%"],"answer":"D","explanation":"At least one=50+30−15=65%.","difficulty":"medium"},{"id":"test_4_math2_q16","module":"math2","questionNumber":16,"type":"stats","skill":"Problem Solving and Data Analysis","passage":"","stem":"In a group of 200 people, 120 prefer coffee, 80 prefer tea, and 40 prefer both. If one person is selected at random, what is the probability they prefer coffee given they prefer tea?","choices":["A) 2/3","B) 1/2","C) 1/3","D) 1/5"],"answer":"B","explanation":"P(coffee|tea)=P(both)/P(tea)=40/80=1/2.","difficulty":"medium"},{"id":"test_4_math2_q17","module":"math2","questionNumber":17,"type":"geometry","skill":"Geometry and Trigonometry","passage":"","stem":"A circle is inscribed in a square of side 14. What is the area inside the square but outside the circle?","choices":["A) 196−14π","B) 49π−196","C) 196−49π","D) 14π"],"answer":"C","explanation":"Square=196. Circle=π(7)²=49π. Difference=196−49π.","difficulty":"medium"},{"id":"test_4_math2_q18","module":"math2","questionNumber":18,"type":"geometry","skill":"Geometry and Trigonometry","passage":"","stem":"Triangle: sides 5, 12, 13. What is the area?","choices":["A) 25","B) 35","C) 60","D) 30"],"answer":"D","explanation":"5²+12²=169=13². Right triangle. Area=½(5)(12)=30.","difficulty":"medium"},{"id":"test_4_math2_q19","module":"math2","questionNumber":19,"type":"geometry","skill":"Geometry and Trigonometry","passage":"","stem":"A cylinder has volume 128π cm³ and height 8 cm. What is the radius?","choices":["A) 2","B) 4","C) 6","D) 8"],"answer":"B","explanation":"128π=πr²(8) → r²=16 → r=4.","difficulty":"medium"},{"id":"test_4_math2_q20","module":"math2","questionNumber":20,"type":"geometry","skill":"Geometry and Trigonometry","passage":"","stem":"A sphere has volume 36π. What is the radius?","choices":["A) 2","B) 3","C) 4","D) 6"],"answer":"B","explanation":"(4/3)πr³=36π → r³=27 → r=3.","difficulty":"medium"},{"id":"test_4_math2_q21","module":"math2","questionNumber":21,"type":"gridin","skill":"Advanced Math","passage":"","stem":"If x+y=12 and x²+y²=80, what is xy?","choices":null,"answer":"32","explanation":"(x+y)²=x²+2xy+y² → 144=80+2xy → xy=32.","difficulty":"medium"},{"id":"test_4_math2_q22","module":"math2","questionNumber":22,"type":"gridin","skill":"Problem Solving and Data Analysis","passage":"","stem":"Scores: 65, 70, 75, 80, x. Mean=73. What is the median?","choices":null,"answer":"75","explanation":"290+x=365 → x=75. Ordered: 65,70,75,75,80. Median=75.","difficulty":"medium"}]}}];
